-- Records of news
-- ----------------------------
INSERT INTO `news` VALUES (2, 'Xu hướng dịch chuyển dòng vốn: Nhà đầu tư săn lùng cơ hội bất động sản 2025', 'Trước tình hình giá cả bất động sản tại Hà Nội tăng vọt, nhu cầu tìm kiếm những kênh đầu tư giá phải chăng ở các đô thị vệ tinh đang trở thành xu hướng của năm nay.', '<p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trong&nbsp;thời&nbsp;điểm&nbsp;thị&nbsp;trường&nbsp;bất&nbsp;động&nbsp;sản&nbsp;Hà&nbsp;Nội&nbsp;chứng&nbsp;kiến&nbsp;sự&nbsp;gia&nbsp;tăng&nbsp;giá&nbsp;cả,&nbsp;nhiều&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;đã&nbsp;phải&nbsp;chuyển&nbsp;hướng&nbsp;tìm&nbsp;kiếm&nbsp;những&nbsp;lựa&nbsp;chọn&nbsp;đầu&nbsp;tư&nbsp;mới&nbsp;với&nbsp;mức&nbsp;giá&nbsp;hợp&nbsp;lý,&nbsp;nhằm&nbsp;đảm&nbsp;bảo&nbsp;lợi&nbsp;nhuận&nbsp;ổn&nbsp;định&nbsp;và&nbsp;giảm&nbsp;thiểu&nbsp;rủi&nbsp;ro.&nbsp;Các&nbsp;phân&nbsp;khúc&nbsp;bất&nbsp;động&nbsp;sản&nbsp;thấp&nbsp;tầng&nbsp;tại&nbsp;các&nbsp;vành&nbsp;đai&nbsp;3,&nbsp;5&nbsp;và&nbsp;4&nbsp;liên&nbsp;tiếp&nbsp;tạo&nbsp;ra&nbsp;mặt&nbsp;bằng&nbsp;giá&nbsp;mới.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/xu-huong-dich-chuyen-dong-von-nha-dau-tu-san-lung-co-hoi-bat-dong-san-20251739841661809_0.jpg\" alt=\"Xu hướng dịch chuyển dòng vốn: Nhà đầu tư săn lùng cơ hội bất động sản 2025 - ảnh 1\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Theo&nbsp;thông&nbsp;báo&nbsp;của&nbsp;Bộ&nbsp;Xây&nbsp;dựng&nbsp;vào&nbsp;tháng&nbsp;1/2025,&nbsp;giá&nbsp;rao&nbsp;bán&nbsp;các&nbsp;căn&nbsp;nhà&nbsp;riêng&nbsp;lẻ&nbsp;trong&nbsp;dự&nbsp;án&nbsp;tại&nbsp;Hà&nbsp;Nội&nbsp;đã&nbsp;tăng&nbsp;từ&nbsp;30-40%&nbsp;so&nbsp;với&nbsp;năm&nbsp;2023;&nbsp;đặc&nbsp;biệt&nbsp;ở&nbsp;một&nbsp;số&nbsp;khu&nbsp;vực,&nbsp;mức&nbsp;tăng&nbsp;có&nbsp;thể&nbsp;lên&nbsp;đến&nbsp;60-70%.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Nhiều&nbsp;dự&nbsp;án&nbsp;hiện&nbsp;đang&nbsp;có&nbsp;giá&nbsp;chào&nbsp;bán&nbsp;trên&nbsp;300&nbsp;triệu&nbsp;đồng/m2,&nbsp;tập&nbsp;trung&nbsp;chủ&nbsp;yếu&nbsp;ở&nbsp;khu&nbsp;vực&nbsp;phía&nbsp;Tây&nbsp;trong&nbsp;phạm&nbsp;vi&nbsp;vành&nbsp;đai&nbsp;3&nbsp;–&nbsp;3,5,&nbsp;cùng&nbsp;với&nbsp;các&nbsp;khu&nbsp;vực&nbsp;Đông&nbsp;Anh&nbsp;và&nbsp;Long&nbsp;Biên.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Tại&nbsp;khu&nbsp;vực&nbsp;phía&nbsp;Tây&nbsp;Hà&nbsp;Nội,&nbsp;trong&nbsp;năm&nbsp;2024,&nbsp;giá&nbsp;bán&nbsp;trung&nbsp;bình&nbsp;của&nbsp;các&nbsp;căn&nbsp;hộ&nbsp;chung&nbsp;cư&nbsp;trong&nbsp;khoảng&nbsp;vành&nbsp;đai&nbsp;3&nbsp;đến&nbsp;3,5&nbsp;dao&nbsp;động&nbsp;từ&nbsp;65&nbsp;-&nbsp;75&nbsp;triệu&nbsp;đồng/m2.&nbsp;Đặc&nbsp;biệt&nbsp;có&nbsp;một&nbsp;số&nbsp;dự&nbsp;án&nbsp;cao&nbsp;cấp&nbsp;có&nbsp;giá&nbsp;trên&nbsp;100&nbsp;triệu&nbsp;đồng/m2.&nbsp;Mức&nbsp;giá&nbsp;của&nbsp;căn&nbsp;hộ&nbsp;chung&nbsp;cư&nbsp;đã&nbsp;tăng&nbsp;khoảng&nbsp;40-50%&nbsp;so&nbsp;với&nbsp;năm&nbsp;2023.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Để&nbsp;sở&nbsp;hữu&nbsp;bất&nbsp;động&nbsp;sản&nbsp;thấp&nbsp;tầng&nbsp;có&nbsp;diện&nbsp;tích&nbsp;khoảng&nbsp;150&nbsp;m2&nbsp;tại&nbsp;những&nbsp;khu&nbsp;vực&nbsp;này,&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;cần&nbsp;đầu&nbsp;tư&nbsp;từ&nbsp;22,5&nbsp;tỷ&nbsp;đến&nbsp;45&nbsp;tỷ&nbsp;đồng.&nbsp;Hay&nbsp;đối&nbsp;với&nbsp;một&nbsp;căn&nbsp;hộ&nbsp;chung&nbsp;cư&nbsp;100&nbsp;m2,&nbsp;mức&nbsp;chi&nbsp;phí&nbsp;khoảng&nbsp;từ&nbsp;6,5&nbsp;tỷ&nbsp;đến&nbsp;trên&nbsp;10&nbsp;tỷ&nbsp;đồng.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Sự&nbsp;chuyển&nbsp;dịch&nbsp;dòng&nbsp;tiền&nbsp;vào&nbsp;những&nbsp;thị&nbsp;trường&nbsp;mới&nbsp;mẻ:&nbsp;Các&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;đổ&nbsp;xô&nbsp;tìm&nbsp;kiếm&nbsp;bất&nbsp;động&nbsp;sản&nbsp;tầm&nbsp;giá&nbsp;vừa&nbsp;phải.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/xu-huong-dich-chuyen-dong-von-nha-dau-tu-san-lung-co-hoi-bat-dong-san-20251739841664003_1.jpg\" alt=\"Xu hướng dịch chuyển dòng vốn: Nhà đầu tư săn lùng cơ hội bất động sản 2025 - ảnh 2\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Giá&nbsp;bất&nbsp;động&nbsp;sản&nbsp;ở&nbsp;các&nbsp;khu&nbsp;vực&nbsp;nội&nbsp;đô&nbsp;đã&nbsp;đạt&nbsp;mức&nbsp;đỉnh&nbsp;cao,&nbsp;khiến&nbsp;không&nbsp;ít&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;gặp&nbsp;khó&nbsp;khăn&nbsp;trong&nbsp;việc&nbsp;tiếp&nbsp;cận.&nbsp;Chính&nbsp;vì&nbsp;vậy,&nbsp;họ&nbsp;ưu&nbsp;tiên&nbsp;tìm&nbsp;kiếm&nbsp;những&nbsp;khu&nbsp;vực&nbsp;cận&nbsp;đô&nbsp;thị&nbsp;và&nbsp;đô&nbsp;thị&nbsp;vệ&nbsp;tinh&nbsp;với&nbsp;tiềm&nbsp;năng&nbsp;tăng&nbsp;giá&nbsp;hứa&nbsp;hẹn.&nbsp;Các&nbsp;yếu&nbsp;tố&nbsp;như&nbsp;hạ&nbsp;tầng&nbsp;kết&nbsp;nối,&nbsp;tốc&nbsp;độ&nbsp;đô&nbsp;thị&nbsp;hóa&nbsp;và&nbsp;nhu&nbsp;cầu&nbsp;thực&nbsp;tiễn&nbsp;từ&nbsp;dân&nbsp;cư&nbsp;địa&nbsp;phương&nbsp;ngày&nbsp;càng&nbsp;được&nbsp;chú&nbsp;trọng.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Ông&nbsp;Phạm&nbsp;Tôn&nbsp;Quyền,&nbsp;Phó&nbsp;Tổng&nbsp;Giám&nbsp;Đốc&nbsp;công&nbsp;ty&nbsp;tư&nbsp;vấn&nbsp;và&nbsp;phát&nbsp;triển&nbsp;bất&nbsp;động&nbsp;sản&nbsp;Grand&nbsp;M,&nbsp;nhận&nbsp;định:&nbsp;&quot;Nhà&nbsp;đầu&nbsp;tư&nbsp;cần&nbsp;đánh&nbsp;giá&nbsp;một&nbsp;cách&nbsp;kỹ&nbsp;lưỡng&nbsp;về&nbsp;hạ&nbsp;tầng&nbsp;giao&nbsp;thông&nbsp;và&nbsp;tốc&nbsp;độ&nbsp;đô&nbsp;thị&nbsp;hóa&nbsp;tại&nbsp;khu&nbsp;vực.&nbsp;Những&nbsp;nơi&nbsp;cận&nbsp;Hà&nbsp;Nội&nbsp;ngày&nbsp;càng&nbsp;thu&nbsp;hút&nbsp;nhờ&nbsp;vào&nbsp;tiềm&nbsp;năng&nbsp;tăng&nbsp;trưởng&nbsp;và&nbsp;giá&nbsp;cả&nbsp;hợp&nbsp;lý.&quot;</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Ngoài&nbsp;Hà&nbsp;Nội,&nbsp;các&nbsp;thành&nbsp;phố&nbsp;như&nbsp;Hải&nbsp;Phòng,&nbsp;Bắc&nbsp;Ninh,&nbsp;Hưng&nbsp;Yên&nbsp;và&nbsp;Quảng&nbsp;Ninh&nbsp;cũng&nbsp;nổi&nbsp;bật&nbsp;nhờ&nbsp;hạ&nbsp;tầng&nbsp;tốt&nbsp;và&nbsp;sự&nbsp;phát&nbsp;triển&nbsp;của&nbsp;ngành&nbsp;công&nbsp;nghiệp.&nbsp;Hơn&nbsp;thế&nbsp;nữa,&nbsp;các&nbsp;dự&nbsp;án&nbsp;đô&nbsp;thị&nbsp;ven&nbsp;biển&nbsp;và&nbsp;sinh&nbsp;thái&nbsp;cũng&nbsp;đã&nbsp;tạo&nbsp;nên&nbsp;xu&nbsp;hướng&nbsp;đầu&nbsp;tư&nbsp;mới,&nbsp;hứa&nbsp;hẹn&nbsp;mang&nbsp;lại&nbsp;giá&nbsp;trị&nbsp;gia&nbsp;tăng&nbsp;đáng&nbsp;kể.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Nhà&nbsp;đầu&nbsp;tư&nbsp;tìm&nbsp;kiếm&nbsp;cơ&nbsp;hội&nbsp;lớn:&nbsp;Dòng&nbsp;vốn&nbsp;đổ&nbsp;về&nbsp;các&nbsp;thị&nbsp;trường&nbsp;mới&nbsp;với&nbsp;phân&nbsp;khúc&nbsp;giá&nbsp;vừa&nbsp;phải.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Nhiều&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;hiện&nbsp;đã&nbsp;chuyển&nbsp;hướng&nbsp;sang&nbsp;các&nbsp;thị&nbsp;trường&nbsp;mới&nbsp;và&nbsp;thu&nbsp;được&nbsp;lợi&nbsp;nhuận&nbsp;ngoài&nbsp;mong&nbsp;đợi.&nbsp;Chẳng&nbsp;hạn,&nbsp;dự&nbsp;án&nbsp;tại&nbsp;Quảng&nbsp;Ninh&nbsp;và&nbsp;Hải&nbsp;Phòng&nbsp;từ&nbsp;năm&nbsp;2022&nbsp;ghi&nbsp;nhận&nbsp;mức&nbsp;lợi&nbsp;nhuận&nbsp;trung&nbsp;bình&nbsp;từ&nbsp;20-30%&nbsp;trong&nbsp;vòng&nbsp;một&nbsp;năm,&nbsp;giúp&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;giảm&nbsp;thiểu&nbsp;rủi&nbsp;ro&nbsp;so&nbsp;với&nbsp;thị&nbsp;trường&nbsp;Hà&nbsp;Nội&nbsp;đang&nbsp;sôi&nbsp;động.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/xu-huong-dich-chuyen-dong-von-nha-dau-tu-san-lung-co-hoi-bat-dong-san-20251739841665682_2.jpg\" alt=\"Xu hướng dịch chuyển dòng vốn: Nhà đầu tư săn lùng cơ hội bất động sản 2025 - ảnh 3\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Bà&nbsp;Nguyễn&nbsp;Hương&nbsp;Giang,&nbsp;một&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;dày&nbsp;dạn&nbsp;kinh&nbsp;nghiệm,&nbsp;chia&nbsp;sẻ:&nbsp;&quot;Việc&nbsp;chuyển&nbsp;dòng&nbsp;vốn&nbsp;vào&nbsp;các&nbsp;khu&nbsp;vực&nbsp;cận&nbsp;đô&nbsp;thị&nbsp;như&nbsp;Hải&nbsp;Phòng&nbsp;giúp&nbsp;tôi&nbsp;không&nbsp;chỉ&nbsp;bảo&nbsp;toàn&nbsp;vốn&nbsp;mà&nbsp;còn&nbsp;đạt&nbsp;được&nbsp;lợi&nbsp;nhuận&nbsp;ổn&nbsp;định.&nbsp;Quan&nbsp;trọng&nbsp;là&nbsp;chọn&nbsp;lựa&nbsp;dự&nbsp;án&nbsp;phù&nbsp;hợp&nbsp;với&nbsp;ngân&nbsp;sách&nbsp;và&nbsp;tiềm&nbsp;năng&nbsp;phát&nbsp;triển&nbsp;của&nbsp;khu&nbsp;vực.&quot;</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trong&nbsp;bối&nbsp;cảnh&nbsp;thị&nbsp;trường&nbsp;đang&nbsp;biến&nbsp;động,&nbsp;các&nbsp;chuyên&nbsp;gia&nbsp;khuyên&nbsp;rằng&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;cần&nbsp;xem&nbsp;xét&nbsp;các&nbsp;tiêu&nbsp;chí&nbsp;cơ&nbsp;bản&nbsp;khi&nbsp;lựa&nbsp;chọn&nbsp;dự&nbsp;án,&nbsp;bao&nbsp;gồm:&nbsp;vị&nbsp;trí&nbsp;thuận&nbsp;lợi,&nbsp;hệ&nbsp;thống&nbsp;giao&nbsp;thông&nbsp;phát&nbsp;triển,&nbsp;tốc&nbsp;độ&nbsp;đô&nbsp;thị&nbsp;hóa&nbsp;nhanh&nbsp;và&nbsp;nhu&nbsp;cầu&nbsp;thực&nbsp;tế&nbsp;của&nbsp;địa&nbsp;phương.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Theo&nbsp;đại&nbsp;diện&nbsp;Hội&nbsp;Môi&nbsp;Giới&nbsp;Bất&nbsp;Động&nbsp;Sản&nbsp;Việt&nbsp;Nam,&nbsp;mặc&nbsp;dù&nbsp;dự&nbsp;án&nbsp;nhà&nbsp;ở&nbsp;mở&nbsp;bán&nbsp;trong&nbsp;năm&nbsp;2025&nbsp;vẫn&nbsp;thu&nbsp;hút&nbsp;sự&nbsp;quan&nbsp;tâm&nbsp;và&nbsp;giao&nbsp;dịch&nbsp;tốt,&nbsp;tốc&nbsp;độ&nbsp;hấp&nbsp;thụ&nbsp;có&nbsp;khả&nbsp;năng&nbsp;chậm&nbsp;lại.&nbsp;Tuy&nbsp;nhiên,&nbsp;nhu&nbsp;cầu&nbsp;nhà&nbsp;ở,&nbsp;đặc&nbsp;biệt&nbsp;là&nbsp;nhu&nbsp;cầu&nbsp;đầu&nbsp;tư,&nbsp;sẽ&nbsp;tiếp&nbsp;tục&nbsp;di&nbsp;chuyển&nbsp;sang&nbsp;các&nbsp;vùng&nbsp;ven&nbsp;đô&nbsp;thị&nbsp;và&nbsp;những&nbsp;tỉnh&nbsp;thành&nbsp;cấp&nbsp;2,&nbsp;cấp&nbsp;3,&nbsp;nơi&nbsp;có&nbsp;giá&nbsp;cả&nbsp;hợp&nbsp;lý&nbsp;và&nbsp;nhiều&nbsp;tiềm&nbsp;năng&nbsp;tăng&nbsp;trưởng&nbsp;trong&nbsp;tương&nbsp;lai.</span></p><p></p>', '/uploads/1781440759640-ha-noi-bo-sung-loat-chinh-sach-ho-tro-boi-thuong-ho-tro-tai-dinh-cu-khi-nha-nuoc-thu-hoi-dat1768884964612_0.jpg', 'Phân tích - Nhận định', '18/02/2025 - 09:02', '2026-06-14 19:13:10');
INSERT INTO `news` VALUES (3, 'Hưng Yên: Tâm điểm đầu tư mới của vùng thủ đô', 'Sau khi sáp nhập, Hưng Yên đã nhanh chóng vươn lên, góp mặt trong danh sách 10 tỉnh có tốc độ tăng trưởng kinh tế ấn tượng nhất cả nước, trở thành một điểm sáng thu hút đầu tư tại cửa ngõ phía Đông Thủ đô.', '<h2><strong style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Hưng&nbsp;Yên&nbsp;-&nbsp;một&nbsp;trong&nbsp;những&nbsp;điểm&nbsp;nổi&nbsp;bật&nbsp;trong&nbsp;quy&nbsp;hoạch&nbsp;mở&nbsp;rộng&nbsp;vùng&nbsp;Thủ&nbsp;đô</strong></h2><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/hung-yen-tam-diem-dau-tu-moi-cua-vung-thu-do1768871844531_0.jpg\" alt=\"Hưng Yên: Tâm điểm đầu tư mới của vùng thủ đô - ảnh 1\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Vùng&nbsp;Thủ&nbsp;đô&nbsp;(vùng&nbsp;Thủ&nbsp;đô&nbsp;Hà&nbsp;Nội)&nbsp;bao&nbsp;gồm&nbsp;Hà&nbsp;Nội&nbsp;cùng&nbsp;9&nbsp;tỉnh&nbsp;lân&nbsp;cận,&nbsp;được&nbsp;quy&nbsp;hoạch&nbsp;với&nbsp;nhiều&nbsp;lần&nbsp;điều&nbsp;chỉnh,&nbsp;gần&nbsp;đây&nbsp;nhất&nbsp;vào&nbsp;năm&nbsp;2016,&nbsp;với&nbsp;mục&nbsp;tiêu&nbsp;đến&nbsp;năm&nbsp;2030&nbsp;và&nbsp;tầm&nbsp;nhìn&nbsp;đến&nbsp;năm&nbsp;2050.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Việc&nbsp;hình&nbsp;thành&nbsp;vùng&nbsp;Thủ&nbsp;đô&nbsp;nhằm&nbsp;tạo&nbsp;ra&nbsp;sự&nbsp;kết&nbsp;nối&nbsp;chặt&nbsp;chẽ&nbsp;về&nbsp;hạ&nbsp;tầng&nbsp;cũng&nbsp;như&nbsp;phát&nbsp;triển&nbsp;kinh&nbsp;tế&nbsp;-&nbsp;xã&nbsp;hội,&nbsp;đồng&nbsp;thời&nbsp;giảm&nbsp;tải&nbsp;dân&nbsp;số&nbsp;cho&nbsp;Hà&nbsp;Nội.&nbsp;Vùng&nbsp;này&nbsp;đóng&nbsp;vai&nbsp;trò&nbsp;là&nbsp;trung&nbsp;tâm&nbsp;kinh&nbsp;tế&nbsp;tổng&nbsp;hợp,&nbsp;chính&nbsp;trị&nbsp;quốc&nbsp;gia&nbsp;với&nbsp;diện&nbsp;tích&nbsp;lên&nbsp;tới&nbsp;hơn&nbsp;24.000&nbsp;km2,&nbsp;trong&nbsp;đó&nbsp;Hà&nbsp;Nội&nbsp;là&nbsp;đô&nbsp;thị&nbsp;hạt&nbsp;nhân&nbsp;và&nbsp;các&nbsp;tỉnh&nbsp;lân&nbsp;cận&nbsp;tạo&nbsp;thành&nbsp;một&nbsp;mạng&nbsp;lưới&nbsp;đô&nbsp;thị&nbsp;đa&nbsp;cực.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trong&nbsp;bức&nbsp;tranh&nbsp;quy&nbsp;hoạch&nbsp;vùng&nbsp;Thủ&nbsp;đô,&nbsp;Hưng&nbsp;Yên&nbsp;chiếm&nbsp;vị&nbsp;trí&nbsp;quan&nbsp;trọng&nbsp;kết&nbsp;nối&nbsp;các&nbsp;đô&nbsp;thị&nbsp;và&nbsp;trung&nbsp;tâm&nbsp;kinh&nbsp;tế&nbsp;chính&nbsp;của&nbsp;miền&nbsp;Bắc,&nbsp;nằm&nbsp;trong&nbsp;tam&nbsp;giác&nbsp;kinh&nbsp;tế&nbsp;phía&nbsp;Nam&nbsp;Hà&nbsp;Nội.&nbsp;Hưng&nbsp;Yên&nbsp;là&nbsp;cầu&nbsp;nối&nbsp;thiết&nbsp;yếu&nbsp;với&nbsp;khu&nbsp;vực&nbsp;trung&nbsp;du&nbsp;miền&nbsp;núi&nbsp;phía&nbsp;Bắc&nbsp;(như&nbsp;Phú&nbsp;Thọ,&nbsp;Lào&nbsp;Cai,&nbsp;Thái&nbsp;Nguyên)&nbsp;nhờ&nbsp;sự&nbsp;phát&nbsp;triển&nbsp;của&nbsp;các&nbsp;tuyến&nbsp;đường&nbsp;liên&nbsp;tỉnh&nbsp;chủ&nbsp;chốt,&nbsp;kết&nbsp;nối&nbsp;trực&nbsp;tiếp&nbsp;với&nbsp;mạng&nbsp;lưới&nbsp;giao&nbsp;thông&nbsp;quốc&nbsp;gia.&nbsp;Đồng&nbsp;thời,&nbsp;Hưng&nbsp;Yên&nbsp;còn&nbsp;là&nbsp;cửa&nbsp;ngõ&nbsp;vận&nbsp;chuyển&nbsp;hàng&nbsp;hóa,&nbsp;nông&nbsp;sản&nbsp;từ&nbsp;các&nbsp;tỉnh&nbsp;miền&nbsp;núi&nbsp;xuống&nbsp;đồng&nbsp;bằng&nbsp;và&nbsp;ra&nbsp;cảng&nbsp;biển&nbsp;như&nbsp;Hải&nbsp;Phòng&nbsp;và&nbsp;Quảng&nbsp;Ninh.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Sau&nbsp;khi&nbsp;sáp&nbsp;nhập&nbsp;với&nbsp;tỉnh&nbsp;Thái&nbsp;Bình,&nbsp;diện&nbsp;tích&nbsp;tỉnh&nbsp;Hưng&nbsp;Yên&nbsp;hiện&nbsp;tại&nbsp;đạt&nbsp;khoảng&nbsp;2.500&nbsp;km2,&nbsp;với&nbsp;dân&nbsp;số&nbsp;vượt&nbsp;3,5&nbsp;triệu&nbsp;người,&nbsp;thuộc&nbsp;nhóm&nbsp;đông&nbsp;dân&nbsp;so&nbsp;với&nbsp;cả&nbsp;nước.&nbsp;Điều&nbsp;này&nbsp;tạo&nbsp;ra&nbsp;lợi&nbsp;thế&nbsp;lớn&nbsp;để&nbsp;mở&nbsp;rộng&nbsp;nền&nbsp;kinh&nbsp;tế&nbsp;địa&nbsp;phương,&nbsp;bảo&nbsp;đảm&nbsp;nguồn&nbsp;nhân&nbsp;lực&nbsp;đa&nbsp;dạng,&nbsp;tạo&nbsp;thêm&nbsp;cơ&nbsp;hội&nbsp;việc&nbsp;làm&nbsp;cho&nbsp;cư&nbsp;dân&nbsp;và&nbsp;thu&nbsp;hút&nbsp;đầu&nbsp;tư&nbsp;mạnh&nbsp;mẽ.</span></p><h2><strong style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Hưng&nbsp;Yên&nbsp;trong&nbsp;thời&nbsp;kỳ&nbsp;phát&nbsp;triển&nbsp;mới</strong></h2><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Vào&nbsp;thế&nbsp;kỷ&nbsp;16-17,&nbsp;Phố&nbsp;Hiến&nbsp;(Hưng&nbsp;Yên)&nbsp;từng&nbsp;là&nbsp;thương&nbsp;cảng&nbsp;sầm&nbsp;uất,&nbsp;điểm&nbsp;đến&nbsp;của&nbsp;nhiều&nbsp;thương&nbsp;nhân&nbsp;trong&nbsp;và&nbsp;ngoài&nbsp;nước.&nbsp;Phố&nbsp;Hiến&nbsp;khi&nbsp;đó&nbsp;được&nbsp;coi&nbsp;là&nbsp;đô&nbsp;thị&nbsp;thương&nbsp;mại&nbsp;phồn&nbsp;thịnh,&nbsp;chỉ&nbsp;sau&nbsp;36&nbsp;phố&nbsp;phường&nbsp;tại&nbsp;kinh&nbsp;thành&nbsp;Thăng&nbsp;Long.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trải&nbsp;qua&nbsp;nhiều&nbsp;năm&nbsp;phát&nbsp;triển,&nbsp;Hưng&nbsp;Yên&nbsp;đã&nbsp;chuyển&nbsp;mình&nbsp;thành&nbsp;vùng&nbsp;kinh&nbsp;tế&nbsp;đa&nbsp;ngành&nbsp;mới&nbsp;của&nbsp;miền&nbsp;Bắc,&nbsp;hiện&nbsp;thuộc&nbsp;top&nbsp;10&nbsp;địa&nbsp;phương&nbsp;có&nbsp;tốc&nbsp;độ&nbsp;tăng&nbsp;trưởng&nbsp;nhanh&nbsp;nhất.&nbsp;Vị&nbsp;trí&nbsp;giữa&nbsp;tam&nbsp;giác&nbsp;kinh&nbsp;tế&nbsp;lớn&nbsp;Hà&nbsp;Nội&nbsp;–&nbsp;Hải&nbsp;Phòng&nbsp;–&nbsp;Quảng&nbsp;Ninh&nbsp;càng&nbsp;củng&nbsp;cố&nbsp;thêm&nbsp;sức&nbsp;hấp&nbsp;dẫn&nbsp;của&nbsp;tỉnh.&nbsp;Đặc&nbsp;biệt&nbsp;trong&nbsp;lĩnh&nbsp;vực&nbsp;công&nbsp;nghiệp,&nbsp;Hưng&nbsp;Yên&nbsp;đã&nbsp;trở&nbsp;thành&nbsp;một&nbsp;điểm&nbsp;đến&nbsp;thu&nbsp;hút&nbsp;đầu&nbsp;tư&nbsp;nước&nbsp;ngoài&nbsp;từ&nbsp;các&nbsp;tập&nbsp;đoàn&nbsp;lớn&nbsp;trên&nbsp;thế&nbsp;giới.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Để&nbsp;đạt&nbsp;được&nbsp;những&nbsp;thành&nbsp;tựu&nbsp;ấn&nbsp;tượng&nbsp;như&nbsp;vậy,&nbsp;Hưng&nbsp;Yên&nbsp;đã&nbsp;ưu&nbsp;tiên&nbsp;đầu&nbsp;tư&nbsp;và&nbsp;phát&nbsp;triển&nbsp;các&nbsp;tuyến&nbsp;giao&nbsp;thông&nbsp;quan&nbsp;trọng&nbsp;như&nbsp;cao&nbsp;tốc&nbsp;Hà&nbsp;Nội&nbsp;–&nbsp;Hải&nbsp;Phòng,&nbsp;vành&nbsp;đai&nbsp;3.5&nbsp;–&nbsp;4,&nbsp;quốc&nbsp;lộ&nbsp;5A&nbsp;và&nbsp;nhiều&nbsp;tuyến&nbsp;đường&nbsp;sắt.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Ngoài&nbsp;việc&nbsp;sở&nbsp;hữu&nbsp;hạ&nbsp;tầng&nbsp;giao&nbsp;thông&nbsp;tiện&nbsp;lợi,&nbsp;Hưng&nbsp;Yên&nbsp;còn&nbsp;là&nbsp;vùng&nbsp;đất&nbsp;có&nbsp;nền&nbsp;văn&nbsp;hóa&nbsp;và&nbsp;lịch&nbsp;sử&nbsp;phong&nbsp;phú,&nbsp;thu&nbsp;hút&nbsp;nhiều&nbsp;du&nbsp;khách&nbsp;hàng&nbsp;năm.&nbsp;Sau&nbsp;khi&nbsp;sáp&nbsp;nhập,&nbsp;tỉnh&nbsp;cũng&nbsp;đã&nbsp;có&nbsp;thêm&nbsp;54&nbsp;km&nbsp;bờ&nbsp;biển&nbsp;với&nbsp;hệ&nbsp;sinh&nbsp;thái&nbsp;đa&nbsp;dạng&nbsp;và&nbsp;nhiều&nbsp;di&nbsp;tích&nbsp;văn&nbsp;hóa&nbsp;–&nbsp;lịch&nbsp;sử&nbsp;quý&nbsp;giá,&nbsp;tạo&nbsp;điều&nbsp;kiện&nbsp;cho&nbsp;ngành&nbsp;du&nbsp;lịch&nbsp;phát&nbsp;triển&nbsp;mạnh&nbsp;mẽ.</span></p><h2><strong style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Cơn&nbsp;sóng&nbsp;đầu&nbsp;tư&nbsp;vào&nbsp;đô&nbsp;thị&nbsp;nghỉ&nbsp;dưỡng</strong></h2><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Ngoài&nbsp;những&nbsp;ưu&nbsp;thế&nbsp;về&nbsp;hạ&nbsp;tầng,&nbsp;chính&nbsp;sách&nbsp;và&nbsp;nguồn&nbsp;nhân&nbsp;lực,&nbsp;Hưng&nbsp;Yên&nbsp;còn&nbsp;được&nbsp;thiên&nbsp;nhiên&nbsp;ưu&nbsp;ái&nbsp;với&nbsp;đất&nbsp;đai&nbsp;màu&nbsp;mỡ&nbsp;ven&nbsp;sông&nbsp;Hồng,&nbsp;sông&nbsp;Luộc,&nbsp;cùng&nbsp;nguồn&nbsp;tài&nbsp;nguyên&nbsp;khoáng&nbsp;sản&nbsp;phong&nbsp;phú.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trong&nbsp;số&nbsp;đó,&nbsp;khoáng&nbsp;nóng&nbsp;được&nbsp;coi&nbsp;là&nbsp;&quot;mỏ&nbsp;vàng&quot;&nbsp;chưa&nbsp;được&nbsp;khai&nbsp;thác&nbsp;đúng&nbsp;mức&nbsp;tại&nbsp;Hưng&nbsp;Yên.&nbsp;Mặc&nbsp;dù&nbsp;được&nbsp;phát&nbsp;hiện&nbsp;muộn&nbsp;so&nbsp;với&nbsp;nhiều&nbsp;nguồn&nbsp;tài&nbsp;nguyên&nbsp;khác,&nbsp;nhưng&nbsp;khoáng&nbsp;nóng&nbsp;tại&nbsp;đây&nbsp;lại&nbsp;có&nbsp;tiềm&nbsp;năng&nbsp;giá&nbsp;trị&nbsp;vô&nbsp;cùng&nbsp;lớn.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Nhiều&nbsp;mạch&nbsp;khoáng&nbsp;nóng&nbsp;đã&nbsp;được&nbsp;phát&nbsp;hiện&nbsp;với&nbsp;chất&nbsp;lượng&nbsp;tốt,&nbsp;cùng&nbsp;với&nbsp;đó&nbsp;là&nbsp;cơ&nbsp;hội&nbsp;phát&nbsp;triển&nbsp;mạnh&nbsp;mẽ&nbsp;cho&nbsp;ngành&nbsp;bất&nbsp;động&nbsp;sản&nbsp;quy&nbsp;mô&nbsp;lớn.&nbsp;Nhiều&nbsp;dự&nbsp;án&nbsp;nổi&nbsp;bật&nbsp;đã&nbsp;xuất&nbsp;hiện&nbsp;như&nbsp;Trump&nbsp;International&nbsp;Hưng&nbsp;Yên,&nbsp;Alluvia&nbsp;City&nbsp;Văn&nbsp;Giang,&nbsp;Vinhomes&nbsp;Ocean&nbsp;Park&nbsp;2,&nbsp;3…</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Nhờ&nbsp;sự&nbsp;thúc&nbsp;đẩy&nbsp;từ&nbsp;quy&nbsp;hoạch&nbsp;vùng&nbsp;Thủ&nbsp;đô,&nbsp;các&nbsp;dự&nbsp;án&nbsp;này&nbsp;đã&nbsp;mở&nbsp;ra&nbsp;chuỗi&nbsp;đô&nbsp;thị&nbsp;sáng&nbsp;tạo,&nbsp;hạ&nbsp;tầng&nbsp;đồng&nbsp;bộ&nbsp;và&nbsp;chất&nbsp;lượng&nbsp;sống&nbsp;cao,&nbsp;tạo&nbsp;cơ&nbsp;hội&nbsp;việc&nbsp;làm&nbsp;cho&nbsp;người&nbsp;dân&nbsp;và&nbsp;thúc&nbsp;đẩy&nbsp;tăng&nbsp;trưởng&nbsp;kinh&nbsp;tế&nbsp;địa&nbsp;phương.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/hung-yen-tam-diem-dau-tu-moi-cua-vung-thu-do1768871847263_1.jpg\" alt=\"Hưng Yên: Tâm điểm đầu tư mới của vùng thủ đô - ảnh 2\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Kịp&nbsp;thời&nbsp;nắm&nbsp;bắt&nbsp;xu&nbsp;hướng&nbsp;này,&nbsp;vào&nbsp;năm&nbsp;2025,&nbsp;sau&nbsp;quá&nbsp;trình&nbsp;khảo&nbsp;sát&nbsp;địa&nbsp;chất&nbsp;và&nbsp;quy&nbsp;hoạch&nbsp;cụ&nbsp;thể,&nbsp;Tập&nbsp;đoàn&nbsp;Onsen&nbsp;Fuji&nbsp;đã&nbsp;gia&nbsp;nhập&nbsp;thị&nbsp;trường&nbsp;với&nbsp;dự&nbsp;án&nbsp;Lynn&nbsp;Times&nbsp;Onsen&nbsp;Retreat&nbsp;Hưng&nbsp;Yên.&nbsp;Dự&nbsp;án&nbsp;này&nbsp;đại&nbsp;diện&nbsp;cho&nbsp;mô&nbsp;hình&nbsp;nghỉ&nbsp;dưỡng&nbsp;trị&nbsp;liệu&nbsp;kết&nbsp;hợp&nbsp;với&nbsp;khoáng&nbsp;nóng&nbsp;tiên&nbsp;phong&nbsp;tại&nbsp;khu&nbsp;vực.</span></p><p class=\"ql-align-justify\"><strong style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Tổ&nbsp;hợp&nbsp;nghỉ&nbsp;dưỡng&nbsp;khoáng&nbsp;nóng&nbsp;cao&nbsp;cấp&nbsp;Đông&nbsp;Hà&nbsp;Nội&nbsp;-&nbsp;Lynn&nbsp;Times&nbsp;Onsen&nbsp;Retreat&nbsp;Hưng&nbsp;Yên</strong></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Lynn&nbsp;Times&nbsp;Onsen&nbsp;Retreat&nbsp;Hưng&nbsp;Yên&nbsp;được&nbsp;xây&nbsp;dựng&nbsp;trên&nbsp;diện&nbsp;tích&nbsp;hơn&nbsp;48&nbsp;ha,&nbsp;với&nbsp;nhiều&nbsp;sản&nbsp;phẩm&nbsp;nổi&nbsp;bật&nbsp;như&nbsp;khu&nbsp;căn&nbsp;hộ&nbsp;trị&nbsp;liệu&nbsp;Thera&nbsp;Home,&nbsp;khu&nbsp;tắm&nbsp;bùn&nbsp;và&nbsp;công&nbsp;viên&nbsp;khoáng&nbsp;nóng,&nbsp;cùng&nbsp;shophouse&nbsp;thương&nbsp;mại.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Điểm&nbsp;đến&nbsp;này&nbsp;không&nbsp;chỉ&nbsp;là&nbsp;một&nbsp;khu&nbsp;du&nbsp;lịch&nbsp;hấp&nbsp;dẫn&nbsp;mà&nbsp;còn&nbsp;được&nbsp;kỳ&nbsp;vọng&nbsp;sẽ&nbsp;trở&nbsp;thành&nbsp;tài&nbsp;sản&nbsp;đầu&nbsp;tư&nbsp;lý&nbsp;tưởng&nbsp;cho&nbsp;cư&nbsp;dân&nbsp;tìm&nbsp;kiếm&nbsp;môi&nbsp;trường&nbsp;sống&nbsp;kết&nbsp;hợp&nbsp;giữa&nbsp;chăm&nbsp;sóc&nbsp;sức&nbsp;khỏe&nbsp;và&nbsp;nghỉ&nbsp;dưỡng.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Với&nbsp;sự&nbsp;tăng&nbsp;trưởng&nbsp;mạnh&nbsp;mẽ&nbsp;sau&nbsp;khi&nbsp;sáp&nbsp;nhập&nbsp;với&nbsp;Thái&nbsp;Bình,&nbsp;Hưng&nbsp;Yên&nbsp;đã&nbsp;từng&nbsp;bước&nbsp;vươn&nbsp;lên&nbsp;mạnh&nbsp;mẽ,&nbsp;phát&nbsp;triển&nbsp;đa&nbsp;ngành&nbsp;hơn,&nbsp;chứng&nbsp;minh&nbsp;đây&nbsp;không&nbsp;chỉ&nbsp;là&nbsp;vùng&nbsp;đệm&nbsp;kinh&nbsp;tế&nbsp;mà&nbsp;thực&nbsp;sự&nbsp;là&nbsp;một&nbsp;cực&nbsp;tăng&nbsp;trưởng&nbsp;độc&nbsp;lập,&nbsp;với&nbsp;nhiều&nbsp;cơ&nbsp;hội&nbsp;đầu&nbsp;tư&nbsp;hấp&nbsp;dẫn&nbsp;cho&nbsp;hiện&nbsp;tại&nbsp;và&nbsp;tương&nbsp;lai&nbsp;nhờ&nbsp;các&nbsp;yếu&nbsp;tố&nbsp;tiện&nbsp;ích&nbsp;cộng&nbsp;hưởng,&nbsp;nổi&nbsp;bật&nbsp;trong&nbsp;quy&nbsp;hoạch&nbsp;vùng&nbsp;Thủ&nbsp;đô&nbsp;mở&nbsp;rộng.</span></p><p></p>', '/uploads/1781502223257-hung-yen-tam-diem-dau-tu-moi-cua-vung-thu-do1768871844531_0.jpg', 'TIN TỨC THỊ TRƯỜNG', '20/01/2026 - 08:37', '2026-06-15 12:43:43');
INSERT INTO `news` VALUES (4, 'Giá chung cư Hà Nội tăng gấp 3', 'Giá căn hộ chung cư tại Hà Nội đã tăng gấp ba lần trong vòng một thập kỷ qua, tạo nên một bức tranh đáng lo ngại cho người dân có mong muốn an cư.', '<p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Theo&nbsp;thống&nbsp;kê,&nbsp;khoảng&nbsp;10&nbsp;năm&nbsp;trước,&nbsp;mức&nbsp;giá&nbsp;trung&nbsp;bình&nbsp;của&nbsp;căn&nbsp;hộ&nbsp;tại&nbsp;Hà&nbsp;Nội&nbsp;dao&nbsp;động&nbsp;từ&nbsp;18&nbsp;đến&nbsp;25&nbsp;triệu&nbsp;đồng/m2.&nbsp;Tuy&nbsp;nhiên,&nbsp;tính&nbsp;đến&nbsp;năm&nbsp;2024-2025,&nbsp;giá&nbsp;bán&nbsp;căn&nbsp;hộ&nbsp;trên&nbsp;thị&nbsp;trường&nbsp;sơ&nbsp;cấp&nbsp;đã&nbsp;vượt&nbsp;qua&nbsp;ngưỡng&nbsp;50-70&nbsp;triệu&nbsp;đồng/m2,&nbsp;đặc&nbsp;biệt&nbsp;là&nbsp;ở&nbsp;những&nbsp;dự&nbsp;án&nbsp;cao&nbsp;cấp&nbsp;tại&nbsp;khu&nbsp;vực&nbsp;trung&nbsp;tâm&nbsp;và&nbsp;phía&nbsp;Tây,&nbsp;giá&nbsp;có&nbsp;thể&nbsp;lên&nbsp;đến&nbsp;100-150&nbsp;triệu&nbsp;đồng/m2.&nbsp;Điều&nbsp;này&nbsp;đồng&nbsp;nghĩa&nbsp;với&nbsp;việc&nbsp;giá&nbsp;căn&nbsp;hộ&nbsp;đã&nbsp;gia&nbsp;tăng&nbsp;gấp&nbsp;ba&nbsp;lần&nbsp;chỉ&nbsp;trong&nbsp;một&nbsp;khoảng&nbsp;thời&nbsp;gian&nbsp;ngắn.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Một&nbsp;minh&nbsp;chứng&nbsp;cụ&nbsp;thể&nbsp;là&nbsp;tổ&nbsp;hợp&nbsp;12&nbsp;tòa&nbsp;chung&nbsp;cư&nbsp;HH&nbsp;tại&nbsp;khu&nbsp;đô&nbsp;thị&nbsp;Linh&nbsp;Đàm,&nbsp;phường&nbsp;Hoàng&nbsp;Liệt,&nbsp;nơi&nbsp;có&nbsp;giá&nbsp;bán&nbsp;căn&nbsp;hộ&nbsp;năm&nbsp;2015&nbsp;rơi&nbsp;vào&nbsp;khoảng&nbsp;13,5-15,5&nbsp;triệu&nbsp;đồng/m2.&nbsp;Sau&nbsp;10&nbsp;năm&nbsp;sử&nbsp;dụng,&nbsp;giá&nbsp;hiện&nbsp;tại&nbsp;đã&nbsp;leo&nbsp;thang&nbsp;lên&nbsp;khoảng&nbsp;35-40&nbsp;triệu&nbsp;đồng/m2&nbsp;cho&nbsp;những&nbsp;căn&nbsp;hộ&nbsp;bình&nbsp;thường,&nbsp;và&nbsp;từ&nbsp;40-45&nbsp;triệu&nbsp;đồng/m2&nbsp;cho&nbsp;những&nbsp;căn&nbsp;có&nbsp;vị&nbsp;trí&nbsp;đẹp&nbsp;và&nbsp;nội&nbsp;thất&nbsp;được&nbsp;cải&nbsp;tạo.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Dự&nbsp;án&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội&nbsp;Đồng&nbsp;Mô&nbsp;Đại&nbsp;Kim&nbsp;(có&nbsp;tên&nbsp;thương&nbsp;mại&nbsp;là&nbsp;Đại&nbsp;Kim&nbsp;Building)&nbsp;cũng&nbsp;đáng&nbsp;chú&nbsp;ý.&nbsp;Giá&nbsp;mở&nbsp;bán&nbsp;ban&nbsp;đầu&nbsp;chỉ&nbsp;gần&nbsp;15&nbsp;triệu&nbsp;đồng/m2,&nbsp;nhưng&nbsp;giờ&nbsp;đây,&nbsp;một&nbsp;số&nbsp;căn&nbsp;hộ&nbsp;đã&nbsp;được&nbsp;rao&nbsp;bán&nbsp;với&nbsp;mức&nbsp;giá&nbsp;lên&nbsp;tới&nbsp;70-80&nbsp;triệu&nbsp;đồng/m2,&nbsp;tức&nbsp;là&nbsp;tăng&nbsp;gấp&nbsp;5&nbsp;lần&nbsp;so&nbsp;với&nbsp;mức&nbsp;giá&nbsp;ban&nbsp;đầu.&nbsp;Thậm&nbsp;chí,&nbsp;những&nbsp;dự&nbsp;án&nbsp;chung&nbsp;cư&nbsp;mới&nbsp;đưa&nbsp;vào&nbsp;sử&nbsp;dụng&nbsp;chưa&nbsp;đến&nbsp;5&nbsp;năm&nbsp;như&nbsp;Phương&nbsp;Đông&nbsp;Green&nbsp;Park&nbsp;ở&nbsp;phường&nbsp;Yên&nbsp;Sở&nbsp;cũng&nbsp;đã&nbsp;chứng&nbsp;kiến&nbsp;sự&nbsp;tăng&nbsp;giá&nbsp;mạnh.&nbsp;Căn&nbsp;hộ&nbsp;tại&nbsp;đây,&nbsp;vốn&nbsp;được&nbsp;mở&nbsp;bán&nbsp;khoảng&nbsp;27-30&nbsp;triệu&nbsp;đồng/m2,&nbsp;giờ&nbsp;đang&nbsp;được&nbsp;chào&nbsp;bán&nbsp;ở&nbsp;mức&nbsp;75-80&nbsp;triệu&nbsp;đồng/m2&nbsp;tùy&nbsp;theo&nbsp;vị&nbsp;trí.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/gia-chung-cu-ha-noi-tang-gap-31758183358221_0.jpg\" alt=\"Giá chung cư Hà Nội tăng gấp 3 - ảnh 1\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Có&nbsp;rất&nbsp;nhiều&nbsp;lý&nbsp;do&nbsp;khiến&nbsp;giá&nbsp;căn&nbsp;hộ&nbsp;tại&nbsp;Hà&nbsp;Nội&nbsp;tăng&nbsp;đột&nbsp;biến&nbsp;trong&nbsp;thập&nbsp;kỷ&nbsp;vừa&nbsp;qua.&nbsp;Các&nbsp;yếu&nbsp;tố&nbsp;như&nbsp;quỹ&nbsp;đất&nbsp;hạn&nbsp;chế,&nbsp;sự&nbsp;chuyển&nbsp;dịch&nbsp;phân&nbsp;khúc&nbsp;sản&nbsp;phẩm&nbsp;khi&nbsp;các&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;tập&nbsp;trung&nbsp;vào&nbsp;phân&nbsp;khúc&nbsp;trung&nbsp;và&nbsp;cao&nbsp;cấp,&nbsp;cùng&nbsp;với&nbsp;sự&nbsp;gia&nbsp;tăng&nbsp;chi&nbsp;phí&nbsp;xây&nbsp;dựng&nbsp;và&nbsp;vật&nbsp;liệu&nbsp;xây&nbsp;dựng,&nbsp;và&nbsp;sự&nbsp;mở&nbsp;rộng&nbsp;hạ&nbsp;tầng&nbsp;đô&nbsp;thị&nbsp;đều&nbsp;góp&nbsp;phần&nbsp;vào&nbsp;việc&nbsp;này.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Mặc&nbsp;dù&nbsp;giá&nbsp;căn&nbsp;hộ&nbsp;tại&nbsp;Hà&nbsp;Nội&nbsp;tăng&nbsp;vọt,&nbsp;thu&nbsp;nhập&nbsp;của&nbsp;người&nbsp;lao&nbsp;động&nbsp;lại&nbsp;không&nbsp;theo&nbsp;kịp.&nbsp;Theo&nbsp;báo&nbsp;cáo&nbsp;từ&nbsp;Viện&nbsp;Nghiên&nbsp;cứu&nbsp;và&nbsp;Đánh&nbsp;giá&nbsp;thị&nbsp;trường&nbsp;bất&nbsp;động&nbsp;sản&nbsp;Việt&nbsp;Nam&nbsp;(VARS&nbsp;IRE),&nbsp;thu&nbsp;nhập&nbsp;bình&nbsp;quân&nbsp;đầu&nbsp;người&nbsp;ở&nbsp;Hà&nbsp;Nội&nbsp;chỉ&nbsp;tăng&nbsp;từ&nbsp;4,1&nbsp;triệu&nbsp;đồng/tháng&nbsp;lên&nbsp;8,3&nbsp;triệu&nbsp;đồng/tháng&nbsp;trong&nbsp;khoảng&nbsp;thời&nbsp;gian&nbsp;từ&nbsp;2014&nbsp;đến&nbsp;giữa&nbsp;năm&nbsp;nay.&nbsp;Điều&nbsp;này&nbsp;dẫn&nbsp;đến&nbsp;khó&nbsp;khăn&nbsp;trong&nbsp;việc&nbsp;hiện&nbsp;thực&nbsp;hóa&nbsp;giấc&nbsp;mơ&nbsp;sở&nbsp;hữu&nbsp;nhà&nbsp;của&nbsp;nhiều&nbsp;người,&nbsp;khi&nbsp;mà&nbsp;giá&nbsp;căn&nbsp;hộ&nbsp;trung&nbsp;bình&nbsp;đã&nbsp;tăng&nbsp;gấp&nbsp;ba,&nbsp;từ&nbsp;25&nbsp;triệu&nbsp;đồng/m2&nbsp;lên&nbsp;75,5&nbsp;triệu&nbsp;đồng/m2.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Vào&nbsp;năm&nbsp;2014,&nbsp;một&nbsp;gia&nbsp;đình&nbsp;có&nbsp;hai&nbsp;lao&nbsp;động&nbsp;với&nbsp;thu&nbsp;nhập&nbsp;trung&nbsp;bình,&nbsp;nếu&nbsp;dành&nbsp;toàn&nbsp;bộ&nbsp;tiền&nbsp;kiếm&nbsp;được&nbsp;chỉ&nbsp;để&nbsp;mua&nbsp;nhà,&nbsp;cũng&nbsp;phải&nbsp;mất&nbsp;tới&nbsp;18&nbsp;năm&nbsp;để&nbsp;tích&nbsp;lũy&nbsp;đủ&nbsp;số&nbsp;tiền&nbsp;1,75&nbsp;tỷ&nbsp;đồng&nbsp;để&nbsp;sở&nbsp;hữu&nbsp;căn&nbsp;hộ&nbsp;70&nbsp;m2&nbsp;với&nbsp;2&nbsp;phòng&nbsp;ngủ.&nbsp;Tuy&nbsp;nhiên,&nbsp;tính&nbsp;đến&nbsp;nay,&nbsp;với&nbsp;mức&nbsp;giá&nbsp;hiện&nbsp;tại&nbsp;cho&nbsp;căn&nbsp;hộ&nbsp;này&nbsp;khoảng&nbsp;5,3&nbsp;tỷ&nbsp;đồng,&nbsp;gia&nbsp;đình&nbsp;ấy&nbsp;sẽ&nbsp;cần&nbsp;tới&nbsp;gần&nbsp;27&nbsp;năm,&nbsp;nếu&nbsp;tiếp&nbsp;tục&nbsp;dành&nbsp;toàn&nbsp;bộ&nbsp;thu&nbsp;nhập&nbsp;để&nbsp;mua&nbsp;nhà.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">VARS&nbsp;IRE&nbsp;cảnh&nbsp;báo&nbsp;rằng,&nbsp;nếu&nbsp;không&nbsp;có&nbsp;các&nbsp;biện&nbsp;pháp&nbsp;chính&nbsp;sách&nbsp;tổng&nbsp;thể&nbsp;nhằm&nbsp;phát&nbsp;triển&nbsp;mạnh&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội&nbsp;và&nbsp;nhà&nbsp;ở&nbsp;phù&nbsp;hợp&nbsp;với&nbsp;túi&nbsp;tiền&nbsp;của&nbsp;người&nbsp;dân,&nbsp;cũng&nbsp;như&nbsp;việc&nbsp;kiểm&nbsp;soát&nbsp;giá&nbsp;cả&nbsp;để&nbsp;tránh&nbsp;tình&nbsp;trạng&nbsp;tăng&nbsp;giá&nbsp;vượt&nbsp;quá&nbsp;thu&nbsp;nhập&nbsp;thực&nbsp;tế,&nbsp;&quot;giấc&nbsp;mơ&nbsp;sở&nbsp;hữu&nbsp;nhà&quot;&nbsp;sẽ&nbsp;vẫn&nbsp;là&nbsp;điều&nbsp;xa&nbsp;vời&nbsp;đối&nbsp;với&nbsp;phần&nbsp;lớn&nbsp;người&nbsp;trẻ&nbsp;trong&nbsp;xã&nbsp;hội&nbsp;hiện&nbsp;nay.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/gia-chung-cu-ha-noi-tang-gap-31758183361665_1.jpg\" alt=\"Giá chung cư Hà Nội tăng gấp 3 - ảnh 2\"></span></p>', '/uploads/1781502381669-canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183062924_1.jpg', 'TIN TỨC THỊ TRƯỜNG', '18/09/2025 - 15:21', '2026-06-15 12:44:21');
INSERT INTO `news` VALUES (5, 'Vượt ngưỡng sức chịu đựng của người mua, giá chung cư Hà Nội sắp tới sẽ như thế nào?', 'Lãnh đạo các công ty bất động sản ở Hà Nội nhận định rằng giá chung cư trong thời gian tới sẽ khó có khả năng tăng lên, do đã vượt qua ngưỡng chịu đựng của người tiêu dùng. Dự báo rằng giá sẽ giữ ổn định cho đến cuối năm 2025, sau đó sẽ bước vào một chu kỳ giảm kéo dài, với mức đáy dự kiến xuất hiện trong giai đoạn từ 2028 đến 2030.', '<p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trong&nbsp;báo&nbsp;cáo&nbsp;về&nbsp;thị&nbsp;trường&nbsp;bất&nbsp;động&nbsp;sản&nbsp;và&nbsp;nhà&nbsp;ở&nbsp;quý&nbsp;I/2025&nbsp;do&nbsp;Bộ&nbsp;Xây&nbsp;dựng&nbsp;công&nbsp;bố,&nbsp;giá&nbsp;bán&nbsp;căn&nbsp;hộ&nbsp;chung&nbsp;cư&nbsp;đã&nbsp;không&nbsp;còn&nbsp;tăng&nbsp;mạnh&nbsp;như&nbsp;năm&nbsp;2024,&nbsp;mà&nbsp;giữ&nbsp;ở&nbsp;mức&nbsp;ổn&nbsp;định.&nbsp;Cụ&nbsp;thể,&nbsp;giá&nbsp;căn&nbsp;hộ&nbsp;thuộc&nbsp;phân&nbsp;khúc&nbsp;bình&nbsp;dân&nbsp;dưới&nbsp;45&nbsp;triệu&nbsp;đồng/m2,&nbsp;phân&nbsp;khúc&nbsp;trung&nbsp;cấp&nbsp;dao&nbsp;động&nbsp;từ&nbsp;45-70&nbsp;triệu&nbsp;đồng/m2,&nbsp;phân&nbsp;khúc&nbsp;cao&nbsp;cấp&nbsp;từ&nbsp;70-100&nbsp;triệu&nbsp;đồng/m2,&nbsp;và&nbsp;riêng&nbsp;phân&nbsp;khúc&nbsp;siêu&nbsp;sang&nbsp;có&nbsp;thể&nbsp;lên&nbsp;đến&nbsp;gần&nbsp;200&nbsp;triệu&nbsp;đồng/m2.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Mặc&nbsp;dù&nbsp;giá&nbsp;chung&nbsp;cư&nbsp;đã&nbsp;giảm&nbsp;dần,&nbsp;nhưng&nbsp;vẫn&nbsp;giữ&nbsp;ở&nbsp;mức&nbsp;cao.&nbsp;Giá&nbsp;chung&nbsp;cư&nbsp;sơ&nbsp;cấp&nbsp;tại&nbsp;Hà&nbsp;Nội&nbsp;hiện&nbsp;khoảng&nbsp;75&nbsp;triệu&nbsp;đồng/m2&nbsp;(chưa&nbsp;bao&nbsp;gồm&nbsp;VAT&nbsp;và&nbsp;phí&nbsp;bảo&nbsp;trì),&nbsp;ghi&nbsp;nhận&nbsp;mức&nbsp;tăng&nbsp;nhẹ&nbsp;so&nbsp;với&nbsp;quý&nbsp;trước&nbsp;đó,&nbsp;theo&nbsp;số&nbsp;liệu&nbsp;từ&nbsp;CBRE.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Báo&nbsp;cáo&nbsp;từ&nbsp;Savills&nbsp;Việt&nbsp;Nam&nbsp;cũng&nbsp;cho&nbsp;thấy&nbsp;rằng&nbsp;thị&nbsp;trường&nbsp;chung&nbsp;cư&nbsp;Hà&nbsp;Nội&nbsp;đã&nbsp;trải&nbsp;qua&nbsp;một&nbsp;giai&nbsp;đoạn&nbsp;với&nbsp;sự&nbsp;tăng&nbsp;giá&nbsp;liên&nbsp;tục&nbsp;trong&nbsp;8&nbsp;quý&nbsp;liên&nbsp;tiếp&nbsp;kể&nbsp;từ&nbsp;quý&nbsp;II/2023,&nbsp;trước&nbsp;khi&nbsp;có&nbsp;dấu&nbsp;hiệu&nbsp;hạ&nbsp;nhiệt&nbsp;trong&nbsp;quý&nbsp;I/2025.&nbsp;Tính&nbsp;đến&nbsp;cuối&nbsp;quý&nbsp;IV/2024,&nbsp;giá&nbsp;chung&nbsp;cư&nbsp;sơ&nbsp;cấp&nbsp;ghi&nbsp;nhận&nbsp;trung&nbsp;bình&nbsp;đạt&nbsp;79&nbsp;triệu&nbsp;đồng/m2,&nbsp;với&nbsp;mức&nbsp;tăng&nbsp;bình&nbsp;quân&nbsp;khoảng&nbsp;22%.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Tuy&nbsp;nhiên,&nbsp;theo&nbsp;khảo&nbsp;sát&nbsp;từ&nbsp;hơn&nbsp;400&nbsp;dự&nbsp;án,&nbsp;thị&nbsp;trường&nbsp;đang&nbsp;chứng&nbsp;kiến&nbsp;sự&nbsp;chững&nbsp;lại&nbsp;rõ&nbsp;rệt&nbsp;của&nbsp;các&nbsp;giao&nbsp;dịch&nbsp;thứ&nbsp;cấp&nbsp;khi&nbsp;giá&nbsp;bán&nbsp;trung&nbsp;bình&nbsp;của&nbsp;căn&nbsp;hộ&nbsp;thứ&nbsp;cấp&nbsp;(chuyển&nbsp;nhượng)&nbsp;trong&nbsp;quý&nbsp;I/2025&nbsp;rơi&nbsp;vào&nbsp;khoảng&nbsp;60&nbsp;triệu&nbsp;đồng/m2,&nbsp;giảm&nbsp;khoảng&nbsp;1%&nbsp;theo&nbsp;quý&nbsp;cho&nbsp;từng&nbsp;dự&nbsp;án,&nbsp;và&nbsp;nhiều&nbsp;căn&nbsp;hộ&nbsp;còn&nbsp;giảm&nbsp;giá&nbsp;mạnh&nbsp;nhưng&nbsp;vẫn&nbsp;không&nbsp;có&nbsp;người&nbsp;mua.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Khảo&nbsp;sát&nbsp;hiện&nbsp;tại&nbsp;chỉ&nbsp;ra&nbsp;rằng&nbsp;giá&nbsp;chung&nbsp;cư&nbsp;rao&nbsp;bán&nbsp;thường&nbsp;dao&nbsp;động&nbsp;từ&nbsp;50&nbsp;triệu&nbsp;đồng/m2&nbsp;trở&nbsp;lên,&nbsp;gần&nbsp;như&nbsp;không&nbsp;còn&nbsp;căn&nbsp;hộ&nbsp;bình&nbsp;dân&nbsp;nào&nbsp;dưới&nbsp;45&nbsp;triệu&nbsp;đồng/m2.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Câu&nbsp;chuyện&nbsp;về&nbsp;sự&nbsp;tăng&nbsp;cao&nbsp;giá&nbsp;chung&nbsp;cư&nbsp;Hà&nbsp;Nội&nbsp;đã&nbsp;trở&nbsp;thành&nbsp;tâm&nbsp;điểm&nbsp;tranh&nbsp;luận&nbsp;từ&nbsp;năm&nbsp;2023.&nbsp;Nhiều&nbsp;quan&nbsp;điểm&nbsp;cho&nbsp;rằng&nbsp;điều&nbsp;này&nbsp;là&nbsp;do&nbsp;cung&nbsp;không&nbsp;đủ&nbsp;đáp&nbsp;ứng&nbsp;cầu&nbsp;và&nbsp;có&nbsp;sự&nbsp;&quot;dẫn&nbsp;dắt&quot;&nbsp;từ&nbsp;những&nbsp;nhà&nbsp;đầu&nbsp;tư.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/vuot-nguong-suc-chiu-dung-cua-nguoi-mua-gia-chung-cu-ha-noi-sap-toi-se-nhu-the-nao1749000648333_0.jpg\" alt=\"Vượt ngưỡng sức chịu đựng của người mua, giá chung cư Hà Nội sắp tới sẽ như thế nào? - ảnh 1\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Một&nbsp;lãnh&nbsp;đạo&nbsp;tại&nbsp;sàn&nbsp;giao&nbsp;dịch&nbsp;bất&nbsp;động&nbsp;sản&nbsp;ở&nbsp;Hà&nbsp;Nội&nbsp;chia&nbsp;sẻ:&nbsp;&quot;Một&nbsp;thị&nbsp;trường&nbsp;với&nbsp;nguồn&nbsp;cung&nbsp;hạn&nbsp;chế&nbsp;và&nbsp;nhu&nbsp;cầu&nbsp;tăng&nbsp;mạnh,&nbsp;đặc&nbsp;biệt&nbsp;khi&nbsp;90%&nbsp;nguồn&nbsp;cung&nbsp;nằm&nbsp;trong&nbsp;tay&nbsp;một&nbsp;số&nbsp;ít&nbsp;chủ&nbsp;đầu&nbsp;tư,&nbsp;thì&nbsp;hiển&nbsp;nhiên&nbsp;giá&nbsp;sẽ&nbsp;bị&nbsp;điều&nbsp;chỉnh&nbsp;bởi&nbsp;thế&nbsp;lực&nbsp;trên&nbsp;thị&nbsp;trường.&quot;</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Một&nbsp;số&nbsp;nhà&nbsp;lãnh&nbsp;đạo&nbsp;doanh&nbsp;nghiệp&nbsp;bất&nbsp;động&nbsp;sản&nbsp;dự&nbsp;đoán&nbsp;rằng&nbsp;giá&nbsp;bán&nbsp;căn&nbsp;hộ&nbsp;chung&nbsp;cư&nbsp;ở&nbsp;Hà&nbsp;Nội&nbsp;sẽ&nbsp;giữ&nbsp;mức&nbsp;ổn&nbsp;định&nbsp;cho&nbsp;đến&nbsp;hết&nbsp;năm&nbsp;2025.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Chia&nbsp;sẻ&nbsp;về&nbsp;dự&nbsp;báo&nbsp;giá&nbsp;căn&nbsp;hộ&nbsp;Hà&nbsp;Nội&nbsp;trong&nbsp;thời&nbsp;gian&nbsp;tới,&nbsp;ông&nbsp;Phạm&nbsp;Đức&nbsp;Toản,&nbsp;CEO&nbsp;Công&nbsp;ty&nbsp;Cổ&nbsp;phần&nbsp;đầu&nbsp;tư&nbsp;và&nbsp;phát&nbsp;triển&nbsp;Bất&nbsp;động&nbsp;sản&nbsp;EZ&nbsp;(EZ&nbsp;Property)&nbsp;cho&nbsp;rằng&nbsp;giá&nbsp;chung&nbsp;cư&nbsp;ở&nbsp;những&nbsp;vị&nbsp;trí&nbsp;trung&nbsp;tâm&nbsp;sẽ&nbsp;có&nbsp;khả&nbsp;năng&nbsp;tăng,&nbsp;nhưng&nbsp;những&nbsp;khu&nbsp;vực&nbsp;khác&nbsp;sẽ&nbsp;không&nbsp;còn&nbsp;khả&nbsp;năng&nbsp;tăng&nbsp;giá&nbsp;do&nbsp;đã&nbsp;đến&nbsp;ngưỡng&nbsp;chịu&nbsp;đựng&nbsp;của&nbsp;người&nbsp;tiêu&nbsp;dùng.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Ông&nbsp;Toản&nbsp;đưa&nbsp;ra&nbsp;3&nbsp;lý&nbsp;do&nbsp;chính&nbsp;cho&nbsp;việc&nbsp;giá&nbsp;chung&nbsp;cư&nbsp;có&nbsp;xu&nbsp;hướng&nbsp;giảm.&nbsp;Thứ&nbsp;nhất,&nbsp;nguồn&nbsp;cung&nbsp;căn&nbsp;hộ&nbsp;sẽ&nbsp;tăng&nbsp;mạnh,&nbsp;đặc&nbsp;biệt&nbsp;là&nbsp;sau&nbsp;khi&nbsp;Hà&nbsp;Nội&nbsp;phê&nbsp;duyệt&nbsp;148&nbsp;dự&nbsp;án&nbsp;với&nbsp;tổng&nbsp;quy&nbsp;mô&nbsp;hơn&nbsp;840&nbsp;ha&nbsp;cho&nbsp;việc&nbsp;phát&nbsp;triển&nbsp;nhà&nbsp;ở&nbsp;thương&nbsp;mại&nbsp;thông&nbsp;qua&nbsp;thỏa&nbsp;thuận&nbsp;nhận&nbsp;quyền&nbsp;sử&nbsp;dụng&nbsp;đất.&nbsp;Những&nbsp;dự&nbsp;án&nbsp;này&nbsp;sẽ&nbsp;bổ&nbsp;sung&nbsp;đáng&nbsp;kể&nbsp;vào&nbsp;nguồn&nbsp;cung&nbsp;bất&nbsp;động&nbsp;sản&nbsp;trong&nbsp;giai&nbsp;đoạn&nbsp;2026-2030.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Thứ&nbsp;hai,&nbsp;việc&nbsp;cải&nbsp;tạo&nbsp;nhà&nbsp;tập&nbsp;thể&nbsp;cũ&nbsp;trong&nbsp;nội&nbsp;đô&nbsp;sẽ&nbsp;tạo&nbsp;ra&nbsp;một&nbsp;lượng&nbsp;cung&nbsp;lớn.&nbsp;Dù&nbsp;không&nbsp;tăng&nbsp;thêm&nbsp;dân&nbsp;số,&nbsp;nhưng&nbsp;những&nbsp;công&nbsp;trình&nbsp;thương&nbsp;mại&nbsp;hoặc&nbsp;công&nbsp;trình&nbsp;hỗn&nbsp;hợp&nbsp;vẫn&nbsp;sẽ&nbsp;có&nbsp;các&nbsp;đơn&nbsp;vị&nbsp;ở&nbsp;như&nbsp;officetel&nbsp;và&nbsp;condotel,&nbsp;mặc&nbsp;dù&nbsp;về&nbsp;mặt&nbsp;pháp&nbsp;lý,&nbsp;người&nbsp;dân&nbsp;không&nbsp;thể&nbsp;cư&nbsp;trú&nbsp;lâu&nbsp;dài.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Cuối&nbsp;cùng,&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội&nbsp;sẽ&nbsp;là&nbsp;yếu&nbsp;tố&nbsp;mang&nbsp;tính&nbsp;chất&nbsp;đột&nbsp;phá,&nbsp;với&nbsp;nhiều&nbsp;khu&nbsp;vực&nbsp;trước&nbsp;đây&nbsp;chỉ&nbsp;xây&nbsp;dựng&nbsp;một&nbsp;vài&nbsp;tòa&nbsp;sẽ&nbsp;được&nbsp;mở&nbsp;rộng&nbsp;quy&nbsp;mô,&nbsp;chẳng&nbsp;hạn&nbsp;như&nbsp;khu&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội&nbsp;Tiên&nbsp;Dương&nbsp;1&nbsp;và&nbsp;Tiên&nbsp;Dương&nbsp;2&nbsp;ở&nbsp;huyện&nbsp;Đông&nbsp;Anh&nbsp;với&nbsp;tổng&nbsp;diện&nbsp;tích&nbsp;gần&nbsp;30&nbsp;ha.&nbsp;Chính&nbsp;vì&nbsp;vậy,&nbsp;nguồn&nbsp;cung&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội&nbsp;trong&nbsp;tương&nbsp;lai&nbsp;sẽ&nbsp;dồi&nbsp;dào,&nbsp;đủ&nbsp;để&nbsp;đáp&nbsp;ứng&nbsp;nhu&nbsp;cầu&nbsp;người&nbsp;dân&nbsp;cần&nbsp;nhà&nbsp;ở&nbsp;giá&nbsp;rẻ.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">&quot;Nếu&nbsp;hiện&nbsp;tại&nbsp;không&nbsp;tập&nbsp;trung&nbsp;phát&nbsp;triển&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội,&nbsp;một&nbsp;số&nbsp;lượng&nbsp;lớn&nbsp;người&nbsp;dân&nbsp;sẽ&nbsp;không&nbsp;thể&nbsp;tiếp&nbsp;cận&nbsp;được&nbsp;nhà&nbsp;ở&nbsp;tại&nbsp;thành&nbsp;phố,&quot;&nbsp;ông&nbsp;Toản&nbsp;nhấn&nbsp;mạnh.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Cùng&nbsp;quan&nbsp;điểm&nbsp;nêu&nbsp;trên,&nbsp;ông&nbsp;Nguyễn&nbsp;Anh&nbsp;Quê,&nbsp;Chủ&nbsp;tịch&nbsp;Tập&nbsp;đoàn&nbsp;G6,&nbsp;cũng&nbsp;dự&nbsp;đoán&nbsp;rằng&nbsp;giá&nbsp;bán&nbsp;chung&nbsp;cư&nbsp;ở&nbsp;Hà&nbsp;Nội&nbsp;sẽ&nbsp;giữ&nbsp;mức&nbsp;ổn&nbsp;định&nbsp;cho&nbsp;đến&nbsp;cuối&nbsp;năm&nbsp;2025,&nbsp;trước&nbsp;khi&nbsp;bước&nbsp;vào&nbsp;giai&nbsp;đoạn&nbsp;giảm&nbsp;giá&nbsp;kéo&nbsp;dài,&nbsp;với&nbsp;đáy&nbsp;rơi&nbsp;vào&nbsp;khoảng&nbsp;thời&nbsp;gian&nbsp;2028&nbsp;-&nbsp;2030,&nbsp;trùng&nbsp;hợp&nbsp;với&nbsp;thời&nbsp;điểm&nbsp;nguồn&nbsp;cung&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội&nbsp;tăng&nbsp;cao.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Theo&nbsp;ông&nbsp;Quê,&nbsp;giá&nbsp;bán&nbsp;chung&nbsp;cư&nbsp;tại&nbsp;Hà&nbsp;Nội&nbsp;có&nbsp;thể&nbsp;giảm&nbsp;từ&nbsp;10-30%&nbsp;so&nbsp;với&nbsp;mức&nbsp;đỉnh&nbsp;của&nbsp;quý&nbsp;IV/2024,&nbsp;tuy&nbsp;mức&nbsp;giảm&nbsp;sẽ&nbsp;khác&nbsp;nhau&nbsp;tùy&nbsp;thuộc&nbsp;vào&nbsp;vị&nbsp;trí&nbsp;cụ&nbsp;thể.&nbsp;Những&nbsp;khu&nbsp;vực&nbsp;nằm&nbsp;trong&nbsp;Vành&nbsp;đai&nbsp;2&nbsp;có&nbsp;thể&nbsp;giữ&nbsp;giá&nbsp;ổn&nbsp;định&nbsp;hoặc&nbsp;tăng&nbsp;nhẹ&nbsp;do&nbsp;khan&nbsp;hiếm&nbsp;quỹ&nbsp;đất&nbsp;và&nbsp;thiếu&nbsp;nguồn&nbsp;cung&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trong&nbsp;khi&nbsp;đó,&nbsp;ở&nbsp;những&nbsp;khu&nbsp;vực&nbsp;từ&nbsp;Vành&nbsp;đai&nbsp;2&nbsp;đến&nbsp;Vành&nbsp;đai&nbsp;3,&nbsp;giá&nbsp;chung&nbsp;cư&nbsp;có&nbsp;khả&nbsp;năng&nbsp;giảm&nbsp;nhẹ&nbsp;từ&nbsp;10-15%,&nbsp;do&nbsp;mặc&nbsp;dù&nbsp;có&nbsp;nguồn&nbsp;cung&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội,&nbsp;nhưng&nbsp;không&nbsp;đủ&nbsp;lớn.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Khu&nbsp;vực&nbsp;ngoài&nbsp;Vành&nbsp;đai&nbsp;3&nbsp;có&nbsp;thể&nbsp;chứng&nbsp;kiến&nbsp;giá&nbsp;căn&nbsp;hộ&nbsp;giảm&nbsp;mạnh&nbsp;từ&nbsp;10-30%,&nbsp;do&nbsp;có&nbsp;nhiều&nbsp;dự&nbsp;án&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội&nbsp;quy&nbsp;mô&nbsp;lớn&nbsp;đang&nbsp;trong&nbsp;quá&nbsp;trình&nbsp;xây&nbsp;dựng,&nbsp;góp&nbsp;phần&nbsp;kéo&nbsp;giãn&nbsp;dân&nbsp;cư&nbsp;đô&nbsp;thị.&nbsp;Tình&nbsp;trạng&nbsp;này&nbsp;khiến&nbsp;giá&nbsp;chung&nbsp;cư&nbsp;đang&nbsp;bán&nbsp;cao&nbsp;giảm&nbsp;mạnh&nbsp;hơn,&nbsp;vì&nbsp;phải&nbsp;cạnh&nbsp;tranh&nbsp;với&nbsp;nhà&nbsp;ở&nbsp;xã&nbsp;hội&nbsp;có&nbsp;giá&nbsp;khoảng&nbsp;20-25&nbsp;triệu&nbsp;đồng/m2.</span></p>', '/uploads/1781502409081-gia-chung-cu-ha-noi-tang-gap-31758183358221_0.jpg', 'TIN TỨC THỊ TRƯỜNG', '04/06/2025 - 08:49', '2026-06-15 12:44:56');
INSERT INTO `news` VALUES (6, 'Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch', 'Nhiều vùng nông thôn ở xã Toàn Lưu, tỉnh Hà Tĩnh gần đây đã trở nên sôi động khi một làn sóng ô tô đổ về, cùng với sự tập trung đông đảo của những người “cò đất” đang tìm kiếm cơ hội mua bán đất nền.', '<p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Vào&nbsp;chiều&nbsp;17/9,&nbsp;phóng&nbsp;viên&nbsp;ghi&nbsp;nhận&nbsp;tại&nbsp;thôn&nbsp;Trung&nbsp;Tâm,&nbsp;xã&nbsp;Ngọc&nbsp;Sơn&nbsp;cũ&nbsp;(nay&nbsp;thuộc&nbsp;xã&nbsp;Toàn&nbsp;Lưu),&nbsp;hàng&nbsp;loạt&nbsp;ô&nbsp;tô&nbsp;đã&nbsp;dừng&nbsp;lại&nbsp;ven&nbsp;đường&nbsp;làng&nbsp;để&nbsp;tham&nbsp;khảo&nbsp;đất,&nbsp;làm&nbsp;cho&nbsp;khu&nbsp;vực&nbsp;yên&nbsp;bình&nbsp;bỗng&nbsp;trở&nbsp;nên&nbsp;ồn&nbsp;ào&nbsp;và&nbsp;nhộn&nbsp;nhịp.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183062924_1.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 2\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183059450_0.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 1\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183064468_2.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 3\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Thôn&nbsp;Trung&nbsp;Tâm&nbsp;cách&nbsp;trụ&nbsp;sở&nbsp;UBND&nbsp;xã&nbsp;Toàn&nbsp;Lưu&nbsp;khoảng&nbsp;hơn&nbsp;10km,&nbsp;và&nbsp;chỉ&nbsp;cách&nbsp;vị&nbsp;trí&nbsp;quy&nbsp;hoạch&nbsp;khu&nbsp;công&nbsp;nghiệp&nbsp;thành&nbsp;phố&nbsp;Hà&nbsp;Tĩnh&nbsp;khoảng&nbsp;5km.&nbsp;Dù&nbsp;địa&nbsp;hình&nbsp;nơi&nbsp;đây&nbsp;chủ&nbsp;yếu&nbsp;là&nbsp;đồi&nbsp;núi&nbsp;và&nbsp;dân&nbsp;cư&nbsp;thưa&nbsp;thớt,&nbsp;nhưng&nbsp;làng&nbsp;quê&nbsp;này&nbsp;gần&nbsp;đây&nbsp;bỗng&nbsp;trở&nbsp;thành&nbsp;tâm&nbsp;điểm&nbsp;trong&nbsp;thị&nbsp;trường&nbsp;bất&nbsp;động&nbsp;sản.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183065625_3.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 4\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Các&nbsp;thông&nbsp;tin&nbsp;cho&nbsp;thấy,&nbsp;nhiều&nbsp;khu&nbsp;đất&nbsp;rộng&nbsp;hàng&nbsp;nghìn&nbsp;mét&nbsp;vuông&nbsp;ở&nbsp;khu&nbsp;vực&nbsp;này&nbsp;đã&nbsp;được&nbsp;tiến&nbsp;hành&nbsp;phân&nbsp;lô,&nbsp;tách&nbsp;thửa,&nbsp;và&nbsp;làm&nbsp;đường&nbsp;tạm&nbsp;để&nbsp;rao&nbsp;bán.&nbsp;Đặc&nbsp;biệt,&nbsp;các&nbsp;lô&nbsp;đất&nbsp;thường&nbsp;được&nbsp;chia&nbsp;nhỏ&nbsp;thành&nbsp;nhiều&nbsp;thửa&nbsp;nhỏ,&nbsp;kèm&nbsp;theo&nbsp;những&nbsp;lời&nbsp;mời&nbsp;chào&nbsp;hấp&nbsp;dẫn&nbsp;như&nbsp;“đất&nbsp;giá&nbsp;rẻ,&nbsp;tiềm&nbsp;năng&nbsp;phát&nbsp;triển”&nbsp;nhất&nbsp;tại&nbsp;Hà&nbsp;Tĩnh.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183066977_4.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 5\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Dọc&nbsp;theo&nbsp;tuyến&nbsp;đường&nbsp;trung&nbsp;tâm&nbsp;xã&nbsp;và&nbsp;lối&nbsp;vào&nbsp;thôn,&nbsp;nhiều&nbsp;ô&nbsp;tô&nbsp;cá&nbsp;nhân&nbsp;đã&nbsp;đậu&nbsp;san&nbsp;sát,&nbsp;còn&nbsp;các&nbsp;môi&nbsp;giới&nbsp;bất&nbsp;động&nbsp;sản&nbsp;thì&nbsp;đứng&nbsp;thành&nbsp;nhóm&nbsp;để&nbsp;chào&nbsp;bán&nbsp;đất&nbsp;ngay&nbsp;tại&nbsp;chỗ.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183068326_5.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 6\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Một&nbsp;số&nbsp;khu&nbsp;đất&nbsp;sau&nbsp;khi&nbsp;được&nbsp;phân&nbsp;lô&nbsp;đã&nbsp;được&nbsp;thảm&nbsp;nhựa,&nbsp;bố&nbsp;trí&nbsp;kẻ&nbsp;vạch&nbsp;vàng&nbsp;hai&nbsp;làn,&nbsp;tạo&nbsp;cảm&nbsp;giác&nbsp;giống&nbsp;như&nbsp;một&nbsp;khu&nbsp;dân&nbsp;cư&nbsp;đang&nbsp;hình&nbsp;thành.&nbsp;Những&nbsp;khu&nbsp;đất&nbsp;này&nbsp;trước&nbsp;kia&nbsp;chủ&nbsp;yếu&nbsp;là&nbsp;đất&nbsp;trồng&nbsp;cây&nbsp;lâu&nbsp;năm,&nbsp;giờ&nbsp;đã&nbsp;được&nbsp;chuyển&nbsp;đổi&nbsp;mục&nbsp;đích&nbsp;sử&nbsp;dụng&nbsp;sang&nbsp;đất&nbsp;ở.&nbsp;Chúng&nbsp;được&nbsp;tách&nbsp;thửa&nbsp;nhỏ&nbsp;với&nbsp;quy&nbsp;mô&nbsp;chiều&nbsp;rộng&nbsp;từ&nbsp;5-7m,&nbsp;chiều&nbsp;dài&nbsp;20m&nbsp;để&nbsp;tiện&nbsp;cho&nbsp;việc&nbsp;rao&nbsp;bán.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183069695_6.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 7\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Thông&nbsp;tin&nbsp;từ&nbsp;các&nbsp;nhóm&nbsp;giới&nbsp;thiệu&nbsp;đất&nbsp;cho&nbsp;hay,&nbsp;giá&nbsp;bán&nbsp;hiện&nbsp;nằm&nbsp;trong&nbsp;khoảng&nbsp;từ&nbsp;500&nbsp;đến&nbsp;700&nbsp;triệu&nbsp;đồng&nbsp;mỗi&nbsp;lô,&nbsp;với&nbsp;diện&nbsp;tích&nbsp;mỗi&nbsp;nền&nbsp;giao&nbsp;động&nbsp;từ&nbsp;120&nbsp;đến&nbsp;140m².&nbsp;Thế&nbsp;nhưng,&nbsp;thực&nbsp;tế&nbsp;cho&nbsp;thấy&nbsp;khu&nbsp;vực&nbsp;này&nbsp;có&nbsp;dân&nbsp;cư&nbsp;thưa&nbsp;thớt&nbsp;và&nbsp;hạ&nbsp;tầng&nbsp;còn&nbsp;thiếu&nbsp;đồng&nbsp;bộ,&nbsp;xa&nbsp;trung&nbsp;tâm&nbsp;xã.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183070835_7.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 8\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Bà&nbsp;Nguyễn&nbsp;Thị&nbsp;L.,&nbsp;50&nbsp;tuổi,&nbsp;một&nbsp;người&nbsp;dân&nbsp;tại&nbsp;thôn&nbsp;Trung&nbsp;Tâm&nbsp;chia&nbsp;sẻ:&nbsp;“Trước&nbsp;đây,&nbsp;chẳng&nbsp;ai&nbsp;để&nbsp;ý&nbsp;đến&nbsp;đất&nbsp;nơi&nbsp;này.&nbsp;Đồi&nbsp;núi&nbsp;cằn&nbsp;cỗi,&nbsp;người&nbsp;dân&nbsp;thưa&nbsp;thớt,&nbsp;ai&nbsp;cũng&nbsp;phải&nbsp;ra&nbsp;thành&nbsp;phố&nbsp;làm&nbsp;việc.&nbsp;Giờ&nbsp;nhìn&nbsp;ô&nbsp;tô&nbsp;chen&nbsp;chúc&nbsp;khắp&nbsp;đường,&nbsp;mọi&nbsp;người&nbsp;đều&nbsp;xôn&nbsp;xao.&nbsp;Đất&nbsp;trồng&nbsp;cây&nbsp;lâu&nbsp;năm&nbsp;giờ&nbsp;được&nbsp;hỏi&nbsp;mua&nbsp;với&nbsp;giá&nbsp;từ&nbsp;500-700&nbsp;ngàn&nbsp;đồng/m²,&nbsp;nhiều&nbsp;hộ&nbsp;gia&nbsp;đình&nbsp;cũng&nbsp;đã&nbsp;bán&nbsp;cả&nbsp;khu&nbsp;vườn&nbsp;và&nbsp;thu&nbsp;về&nbsp;hàng&nbsp;tỷ&nbsp;đồng.”</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183072312_8.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 9\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Theo&nbsp;thông&nbsp;tin&nbsp;từ&nbsp;người&nbsp;dân&nbsp;địa&nbsp;phương,&nbsp;phần&nbsp;lớn&nbsp;khu&nbsp;đất&nbsp;được&nbsp;rao&nbsp;bán&nbsp;trước&nbsp;đây&nbsp;thực&nbsp;chất&nbsp;là&nbsp;rừng&nbsp;trồng&nbsp;hay&nbsp;đất&nbsp;đồi&nbsp;khô&nbsp;cằn,&nbsp;chủ&nbsp;yếu&nbsp;được&nbsp;dùng&nbsp;để&nbsp;trồng&nbsp;cây&nbsp;lấy&nbsp;gỗ&nbsp;hoặc&nbsp;để&nbsp;bỏ&nbsp;hoang,&nbsp;chưa&nbsp;từng&nbsp;ghi&nbsp;nhận&nbsp;giao&nbsp;dịch&nbsp;mua&nbsp;bán&nbsp;nhà&nbsp;đất&nbsp;nhộn&nbsp;nhịp&nbsp;như&nbsp;hiện&nbsp;tại.&nbsp;Sự&nbsp;đổ&nbsp;bộ&nbsp;của&nbsp;các&nbsp;nhóm&nbsp;môi&nbsp;giới&nbsp;và&nbsp;nhà&nbsp;đầu&nbsp;tư&nbsp;đã&nbsp;khiến&nbsp;cư&nbsp;dân&nbsp;không&nbsp;khỏi&nbsp;hoang&nbsp;mang&nbsp;và&nbsp;lo&nbsp;lắng.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183074174_9.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 10\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Đối&nbsp;diện&nbsp;với&nbsp;tình&nbsp;trạng&nbsp;bất&nbsp;thường&nbsp;này,&nbsp;nhiều&nbsp;người&nbsp;dân&nbsp;địa&nbsp;phương&nbsp;hy&nbsp;vọng&nbsp;chính&nbsp;quyền&nbsp;sẽ&nbsp;sớm&nbsp;vào&nbsp;cuộc&nbsp;để&nbsp;kiểm&nbsp;tra&nbsp;và&nbsp;kiểm&nbsp;soát&nbsp;quy&nbsp;hoạch,&nbsp;ngăn&nbsp;chặn&nbsp;tình&nbsp;trạng&nbsp;phân&nbsp;lô&nbsp;bán&nbsp;đất&nbsp;nhằm&nbsp;tránh&nbsp;đầu&nbsp;cơ&nbsp;và&nbsp;gây&nbsp;xáo&nbsp;trộn&nbsp;cho&nbsp;thị&nbsp;trường,&nbsp;đồng&nbsp;thời&nbsp;ảnh&nbsp;hưởng&nbsp;đến&nbsp;đời&nbsp;sống&nbsp;người&nbsp;dân&nbsp;địa&nbsp;phương.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/canh-tuong-co-dat-un-un-do-ve-o-to-dau-kin-duong-lang-sau-cong-bo-quy-hoach1758183075297_10.jpg\" alt=\"Cảnh tượng ‘cò đất’ ùn ùn đổ về, ô tô đậu kín đường làng sau công bố quy hoạch - ảnh 11\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trao&nbsp;đổi&nbsp;với&nbsp;Tiền&nbsp;Phong,&nbsp;lãnh&nbsp;đạo&nbsp;UBND&nbsp;xã&nbsp;Toàn&nbsp;Lưu&nbsp;cho&nbsp;biết,&nbsp;sau&nbsp;khi&nbsp;công&nbsp;bố&nbsp;quy&nbsp;hoạch&nbsp;phân&nbsp;khu&nbsp;cho&nbsp;Khu&nbsp;công&nbsp;nghiệp&nbsp;phía&nbsp;Tây&nbsp;thành&nbsp;phố&nbsp;Hà&nbsp;Tĩnh,&nbsp;thị&nbsp;trường&nbsp;bất&nbsp;động&nbsp;sản&nbsp;tại&nbsp;nơi&nbsp;đây&nbsp;đã&nbsp;có&nbsp;dấu&nbsp;hiệu&nbsp;sốt&nbsp;giá,&nbsp;ở&nbsp;một&nbsp;số&nbsp;vùng&nbsp;giá&nbsp;đất&nbsp;tăng&nbsp;lên&nbsp;tới&nbsp;40%.&nbsp;Tuy&nbsp;nhiên,&nbsp;đại&nbsp;diện&nbsp;địa&nbsp;phương&nbsp;khẳng&nbsp;định&nbsp;đây&nbsp;là&nbsp;một&nbsp;cơn&nbsp;“sốt&nbsp;ảo”&nbsp;do&nbsp;giới&nbsp;đầu&nbsp;cơ&nbsp;và&nbsp;“cò&nbsp;đất”&nbsp;tạo&nbsp;ra,&nbsp;thực&nbsp;tế&nbsp;nhu&nbsp;cầu&nbsp;đất&nbsp;ở&nbsp;tại&nbsp;khu&nbsp;vực&nbsp;không&nbsp;lớn.&nbsp;Chính&nbsp;quyền&nbsp;địa&nbsp;phương&nbsp;cũng&nbsp;đã&nbsp;chủ&nbsp;động&nbsp;tuyên&nbsp;truyền,&nbsp;khuyến&nbsp;cáo&nbsp;người&nbsp;dân&nbsp;không&nbsp;nên&nbsp;chạy&nbsp;theo&nbsp;cơn&nbsp;sốt&nbsp;ảo,&nbsp;tránh&nbsp;việc&nbsp;vay&nbsp;mượn&nbsp;và&nbsp;đặt&nbsp;cọc&nbsp;mua&nbsp;đất&nbsp;trong&nbsp;tình&nbsp;trạng&nbsp;hiện&nbsp;nay.</span></p>', '/uploads/1781502641947-hung-yen-tam-diem-dau-tu-moi-cua-vung-thu-do1768871847263_1.jpg', 'TIN TỨC THỊ TRƯỜNG', '18/09/2025 - 15:14', '2026-06-15 12:45:36');
INSERT INTO `news` VALUES (7, 'Hà Nội: Bổ sung danh mục 72 dự án thu hồi đất năm 2025', 'UBND Thành phố Hà Nội đã có văn bản gửi đến Hội đồng Nhân dân Thành phố, trong đó nêu rõ đề nghị bổ sung danh sách 72 dự án thu hồi đất cho năm 2025, với tổng diện tích lên đến 1.006,25ha. Đặc biệt, huyện Đông Anh đóng góp số lượng dự án áp đảo với 38 công trình.', '<p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">UBND&nbsp;Thành&nbsp;phố&nbsp;Hà&nbsp;Nội&nbsp;đã&nbsp;trình&nbsp;bày&nbsp;đề&nbsp;xuất&nbsp;điều&nbsp;chỉnh,&nbsp;bổ&nbsp;sung&nbsp;danh&nbsp;mục&nbsp;các&nbsp;dự&nbsp;án&nbsp;thu&nbsp;hồi&nbsp;đất&nbsp;cùng&nbsp;các&nbsp;dự&nbsp;án&nbsp;chuyển&nbsp;mục&nbsp;đích&nbsp;sử&nbsp;dụng&nbsp;đất&nbsp;trồng&nbsp;lúa&nbsp;tại&nbsp;địa&nbsp;bàn.&nbsp;Đến&nbsp;ngày&nbsp;12/6,&nbsp;có&nbsp;tới&nbsp;14&nbsp;quận,&nbsp;huyện&nbsp;đã&nbsp;gửi&nbsp;báo&nbsp;cáo&nbsp;đề&nbsp;nghị&nbsp;liên&nbsp;quan&nbsp;đến&nbsp;việc&nbsp;điều&nbsp;chỉnh&nbsp;các&nbsp;dự&nbsp;án&nbsp;trong&nbsp;kế&nbsp;hoạch&nbsp;thu&nbsp;hồi&nbsp;đất&nbsp;năm&nbsp;2025.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\"><img src=\"https://cdn.xemnha.vn/images/ha-noi-bo-sung-danh-muc-72-du-an-thu-hoi-dat-nam-20251750814864977_0.jpg\" alt=\"Hà Nội: Bổ sung danh mục 72 dự án thu hồi đất năm 2025 - ảnh 1\"></span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Theo&nbsp;thông&nbsp;tin&nbsp;từ&nbsp;UBND&nbsp;Thành&nbsp;phố,&nbsp;việc&nbsp;điều&nbsp;chỉnh&nbsp;một&nbsp;số&nbsp;dự&nbsp;án&nbsp;là&nbsp;cần&nbsp;thiết,&nbsp;sau&nbsp;khi&nbsp;tiến&nbsp;hành&nbsp;kiểm&nbsp;tra&nbsp;và&nbsp;xác&nbsp;định&nbsp;ranh&nbsp;giới&nbsp;để&nbsp;phục&nbsp;vụ&nbsp;công&nbsp;tác&nbsp;giải&nbsp;phóng&nbsp;mặt&nbsp;bằng.&nbsp;Các&nbsp;huyện&nbsp;cũng&nbsp;đã&nbsp;thực&nbsp;hiện&nbsp;việc&nbsp;khảo&nbsp;sát&nbsp;và&nbsp;kiểm&nbsp;đếm&nbsp;diện&nbsp;tích,&nbsp;loại&nbsp;đất&nbsp;liên&nbsp;quan&nbsp;đến&nbsp;từng&nbsp;dự&nbsp;án.&nbsp;Nhiều&nbsp;dự&nbsp;án&nbsp;đã&nbsp;được&nbsp;phê&nbsp;duyệt&nbsp;hoặc&nbsp;điều&nbsp;chỉnh,&nbsp;trong&nbsp;đó&nbsp;có&nbsp;thay&nbsp;đổi&nbsp;về&nbsp;quy&nbsp;mô&nbsp;đất&nbsp;sử&nbsp;dụng.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">UBND&nbsp;Thành&nbsp;phố&nbsp;đề&nbsp;xuất&nbsp;bổ&nbsp;sung&nbsp;và&nbsp;điều&nbsp;chỉnh&nbsp;nội&nbsp;dung&nbsp;của&nbsp;các&nbsp;dự&nbsp;án&nbsp;đã&nbsp;được&nbsp;ghi&nbsp;trong&nbsp;Nghị&nbsp;quyết&nbsp;số&nbsp;69/NQ-HĐND&nbsp;ngày&nbsp;12/12/2024.&nbsp;Cụ&nbsp;thể,&nbsp;sẽ&nbsp;điều&nbsp;chỉnh&nbsp;tăng&nbsp;diện&nbsp;tích&nbsp;đất&nbsp;thu&nbsp;hồi&nbsp;tại&nbsp;6&nbsp;dự&nbsp;án&nbsp;với&nbsp;tổng&nbsp;diện&nbsp;tích&nbsp;đạt&nbsp;17,54ha;&nbsp;bổ&nbsp;sung&nbsp;thêm&nbsp;1,77ha&nbsp;đất&nbsp;trồng&nbsp;lúa&nbsp;cho&nbsp;3&nbsp;dự&nbsp;án;&nbsp;và&nbsp;bổ&nbsp;sung&nbsp;toàn&nbsp;bộ&nbsp;72&nbsp;dự&nbsp;án&nbsp;thu&nbsp;hồi&nbsp;đất&nbsp;với&nbsp;tổng&nbsp;diện&nbsp;tích&nbsp;1.006,25ha.&nbsp;Ngoài&nbsp;ra,&nbsp;còn&nbsp;có&nbsp;5&nbsp;dự&nbsp;án&nbsp;chuyển&nbsp;đổi&nbsp;mục&nbsp;đích&nbsp;sử&nbsp;dụng&nbsp;đất&nbsp;trồng&nbsp;lúa,&nbsp;với&nbsp;tổng&nbsp;diện&nbsp;tích&nbsp;56,69ha.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Trong&nbsp;số&nbsp;72&nbsp;dự&nbsp;án&nbsp;được&nbsp;bổ&nbsp;sung,&nbsp;huyện&nbsp;Đông&nbsp;Anh&nbsp;chiếm&nbsp;ưu&nbsp;thế&nbsp;với&nbsp;38&nbsp;dự&nbsp;án.&nbsp;Nổi&nbsp;bật&nbsp;trong&nbsp;số&nbsp;này&nbsp;là&nbsp;các&nbsp;dự&nbsp;án&nbsp;phát&nbsp;triển&nbsp;cơ&nbsp;sở&nbsp;hạ&nbsp;tầng&nbsp;quan&nbsp;trọng&nbsp;như&nbsp;Dự&nbsp;án&nbsp;xây&nbsp;dựng&nbsp;đường&nbsp;kết&nbsp;nối&nbsp;cầu&nbsp;Tứ&nbsp;Liên&nbsp;và&nbsp;Dự&nbsp;án&nbsp;xây&nbsp;dựng&nbsp;tuyến&nbsp;đường&nbsp;từ&nbsp;Hoàng&nbsp;Sa&nbsp;đến&nbsp;đường&nbsp;sắt&nbsp;Hà&nbsp;Nội&nbsp;-&nbsp;Lào&nbsp;Cai.</span></p><p class=\"ql-align-justify\"><span style=\"background-color: rgb(255, 255, 255); color: rgb(63, 52, 36);\">Dự&nbsp;kiến,&nbsp;đề&nbsp;xuất&nbsp;này&nbsp;sẽ&nbsp;được&nbsp;Hội&nbsp;đồng&nbsp;Nhân&nbsp;dân&nbsp;Thành&nbsp;phố&nbsp;xem&nbsp;xét&nbsp;và&nbsp;thông&nbsp;qua&nbsp;trong&nbsp;kỳ&nbsp;họp&nbsp;lần&nbsp;thứ&nbsp;24,&nbsp;dự&nbsp;kiến&nbsp;diễn&nbsp;ra&nbsp;vào&nbsp;ngày&nbsp;27/6.</span></p><p></p>', '/uploads/1781502685176-hung-yen-tam-diem-dau-tu-moi-cua-vung-thu-do1768871844531_0.jpg', 'TIN TỨC THỊ TRƯỜNG', '25/06/2025 - 08:29', '2026-06-15 12:51:25');

-- ----------------------------
-- Table structure for projects
-- ----------------------------
DROP TABLE IF EXISTS `projects`;
CREATE TABLE `projects`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `title` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `description` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL,
  `location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `price` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `area` int NULL DEFAULT NULL,
  `bedrooms` int NULL DEFAULT NULL,
  `bathrooms` int NULL DEFAULT NULL,
  `mainImg` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `sideImg` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `badge` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `isFeatured` tinyint(1) NULL DEFAULT 0,
  `type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT 'listing',
  `createdAt` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `images` json NULL,
  `category` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `views` int NULL DEFAULT 0,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of projects
-- ----------------------------
INSERT INTO `projects` VALUES (3, 'CHÍNH CHỦ BÁN CĂN NHÀ VƯỜN 120m2 KĐT GELEXIMCO LÊ TRỌNG TẤN GIÁ SIÊU RẺ', 'Thông tin mô tả:\r\nHiện tại không có nhu cầu sử dụng, chính chủ gửi bán căn nhà vườn 120m2 KĐT Geleximco Lê Trọng Tấn với giá siêu tốt:\r\n- Mặt tiền 6m, diện tích sổ 120m2\r\n- Nhà không một lỗi nhỏ, xung quanh hàng xóm về ở đông vuii\r\n- View trường học, gần ngay vườn hoaa\r\n- Đường trước nhà 13.5m, 3 làn xe tránh nhau dễ dàngg\r\n- Sổ đỏ cầm tay, sang tên trong ngàyy\r\n\r\nLhe xem nhà: Ms Nga 0822495777\r\nĐặc điểm bất động sản\r\nĐịa chỉ:\r\nPhường Dương Nội, Quận Hà Đông, Hà Nội\r\nĐặc điểm nổi trội:\r\n- Mặt tiền rộng\r\nDiện tích sử dụng:\r\n120\r\nGiấy tờ pháp lý:\r\nSổ đỏ\r\nGiá/m²:\r\n171 Triệu/m²\r\nMặt tiền:\r\n6\r\nĐường trước nhà/đất:\r\n13.5\r\nChiều sâu:\r\n20\r\nHướng nhà/đất:\r\n---\r\nThông tin khác\r\nTổng số tầng:\r\n4\r\nHướng ban công:\r\n---\r\nSố phòng ngủ:\r\n5\r\nSố phòng vệ sinh:\r\n4\r\nNội thất:\r\nXây thô hoàn thiện mặt ngoài\r\nMã tin: 84973\r\nLoại tin: Bán Biệt thự, nhà liền kề\r\n2 năm trước\r\nNgày hết hạn: 28/11/2024', 'Dương Nội, Quận Hà Đông, Thành phố Hà Nội', '20.5 Tỷ ', 120, NULL, NULL, '/uploads/1781440067794-ha-noi-bo-sung-loat-chinh-sach-ho-tro-boi-thuong-ho-tro-tai-dinh-cu-khi-nha-nuoc-thu-hoi-dat1768884964612_0.jpg', '/uploads/1781440067808-z4730767781633_2798e9442b7f12d4b0eff48546b1dbac.jpg', NULL, 1, 'tailored', '2026-06-14 19:06:31', '[\"/uploads/1781440067794-ha-noi-bo-sung-loat-chinh-sach-ho-tro-boi-thuong-ho-tro-tai-dinh-cu-khi-nha-nuoc-thu-hoi-dat1768884964612_0.jpg\", \"/uploads/1781440067808-z4730767781633_2798e9442b7f12d4b0eff48546b1dbac.jpg\", \"/uploads/1781440067809-z4746510817891_9c6b0d023fd454d5f78e59ec2e484e95.jpg\", \"/uploads/1781440067811-z4746520930905_73f2562f91dc9b08dfaa022978737a58.jpg\"]', 'BÁN CĂN HỘ CHUNG CƯ', 32);

