INSERT INTO `spaces` VALUES (6, 'SAIGON', 'Ngoại thất', 'Masteri Cao Xà Lá', 'Masteri Cao Xà Lá là dự án đô thị quy mô lớn tọa lạc tại số 233 – 235 Nguyễn Trãi', '[\"/uploads/1781503148199-phoi-canh-masteri-cao-xa-la-3.png\", \"/uploads/1781503148206-phoi-xanh-masteri-cao-xa-la-1.png\", \"/uploads/1781503148216-phoi-xanh-masteri-cao-xa-la-2.png\", \"/uploads/1781503148225-vi-tri-masteri-cao-xa-la-1.png\"]', '', '2026-06-15 12:59:08');

